def read_runtime(path: Path) -> dict[str, object] | None:
    if not path.exists():
        return None
    return json.loads(path.read_text(encoding="utf-8"))


def read_plugin_runtime_requirements_version(paths: dict[str, Path] | None) -> str | None:
    if paths is None:
        return None
    marker_path = paths["requirements_marker_path"]
    if not marker_path.exists():
        return None
    return normalize_whitespace(marker_path.read_text(encoding="utf-8")) or None


def write_plugin_runtime_requirements_version(paths: dict[str, Path], version: str) -> None:
    paths["requirements_marker_path"].write_text(f"{version}\n", encoding="utf-8")


def activate_plugin_site_packages(paths: dict[str, Path] | None) -> bool:
    if paths is None:
        return False
    site_packages_path = first_existing_plugin_runtime_site_packages(paths)
    if site_packages_path is None:
        return False
    try:
        resolved = str(site_packages_path.resolve())
    except OSError:
        resolved = str(site_packages_path)
    if resolved in ACTIVATED_PLUGIN_SITE_PACKAGES or resolved in sys.path:
        ACTIVATED_PLUGIN_SITE_PACKAGES.add(resolved)
        return True
    site.addsitedir(resolved)
    ACTIVATED_PLUGIN_SITE_PACKAGES.add(resolved)
    return True


def describe_plugin_runtime(paths: dict[str, Path] | None) -> dict[str, object]:
    if paths is None:
        return {
            "status": "unavailable",
            "detail": "Shared plugin runtime path could not be determined from the current plugin installation.",
            "mode": "shared",
            "plugin_root": None,
            "runtime_root": None,
            "venv_present": False,
            "python_executable": None,
            "site_packages_path": None,
            "requirements_version": None,
        }
    venv_dir_present = paths["venv_dir"].exists()
    python_present = paths["venv_python_path"].exists()
    site_packages_path = first_existing_plugin_runtime_site_packages(paths)
    installed_requirements_version = read_plugin_runtime_requirements_version(paths)
    if python_present and installed_requirements_version == REQUIREMENTS_VERSION:
        status = "pass"
        detail = "Shared plugin runtime and pinned requirements are ready."
    elif python_present:
        status = "partial"
        detail = "Shared plugin runtime exists, but the pinned requirements are not fully installed yet."
    elif venv_dir_present:
        status = "partial"
        detail = "Shared plugin runtime directory exists, but the Python executable is missing."
    else:
        status = "missing"
        detail = "Shared plugin runtime has not been initialized yet."
    return {
        "status": status,
        "detail": detail,
        "mode": "shared",
        "plugin_root": str(paths["plugin_root"]),
        "runtime_root": str(paths["runtime_root"]),
        "venv_present": venv_dir_present,
        "python_executable": str(paths["venv_python_path"]) if python_present else None,
        "site_packages_path": str(site_packages_path) if site_packages_path is not None else None,
        "requirements_version": installed_requirements_version,
    }


def ensure_plugin_runtime_layout(paths: dict[str, Path]) -> None:
    paths["runtime_root"].mkdir(parents=True, exist_ok=True)
    paths["locks_dir"].mkdir(parents=True, exist_ok=True)


def ensure_plugin_venv(paths: dict[str, Path]) -> dict[str, object]:
    ensure_plugin_runtime_layout(paths)
    venv_dir = paths["venv_dir"]
    created = not paths["venv_python_path"].exists()
    if created:
        builder = venv.EnvBuilder(with_pip=True)
        builder.create(venv_dir)
    if not paths["venv_python_path"].exists():
        raise RetrieverError(
            f"Plugin runtime initialization did not create a Python executable at {paths['venv_python_path']}"
        )
    return {
        "created": created,
        "python_executable": str(paths["venv_python_path"]),
    }


def install_plugin_runtime_requirements(
    paths: dict[str, Path],
    requirements: list[str] | tuple[str, ...],
    *,
    reason: str,
) -> dict[str, object]:
    python_path = paths["venv_python_path"]
    if not python_path.exists():
        raise RetrieverError(f"Plugin runtime Python not found at {python_path}")
    command = [
        str(python_path),
        "-m",
        "pip",
        "install",
        "--disable-pip-version-check",
        *list(requirements),
    ]
    completed = subprocess.run(command, capture_output=True, text=True)
    if completed.returncode != 0:
        detail = normalize_whitespace(completed.stderr or completed.stdout) or f"pip exited with status {completed.returncode}"
        raise RetrieverError(f"Plugin runtime install failed for {reason}: {detail}")
    write_plugin_runtime_requirements_version(paths, REQUIREMENTS_VERSION)
    return {
        "installed": True,
        "reason": reason,
        "command": command,
        "requirements_version": REQUIREMENTS_VERSION,
    }


def ensure_plugin_runtime(
    paths: dict[str, Path] | None,
    *,
    install_requirements: bool,
    force_requirements_install: bool = False,
    reason: str,
) -> dict[str, object]:
    if paths is None:
        raise RetrieverError("Could not determine the shared plugin runtime location for this Retriever installation.")
    ensure_plugin_runtime_layout(paths)
    lock_handle = acquire_plugin_runtime_install_lock(paths)
    try:
        venv_result = ensure_plugin_venv(paths)
        activate_plugin_site_packages(paths)
        installed_requirements_version = read_plugin_runtime_requirements_version(paths)
        requirements_installed = False
        if install_requirements and (
            force_requirements_install
            or installed_requirements_version != REQUIREMENTS_VERSION
        ):
            install_plugin_runtime_requirements(paths, PINNED_RUNTIME_REQUIREMENTS, reason=reason)
            installed_requirements_version = REQUIREMENTS_VERSION
            requirements_installed = True
            activate_plugin_site_packages(paths)
        runtime_status = describe_plugin_runtime(paths)
        return {
            "status": runtime_status["status"],
            "detail": runtime_status["detail"],
            "venv_created": bool(venv_result["created"]),
            "requirements_installed": requirements_installed,
            "requirements_version": installed_requirements_version,
            "python_executable": runtime_status["python_executable"],
        }
    finally:
        release_plugin_runtime_install_lock(lock_handle)


def read_workspace_meta(connection: sqlite3.Connection) -> dict[str, object] | None:
    if not table_exists(connection, "workspace_meta"):
        return None
    row = connection.execute(
        """
        SELECT
          id, schema_version, tool_version, requirements_version,
          template_source, template_sha256, created_at, updated_at
        FROM workspace_meta
        WHERE id = 1
        """
    ).fetchone()
    if row is None:
        return None
    return {key: row[key] for key in row.keys()}


def write_runtime(paths: dict[str, Path], tool_sha256: str | None) -> dict[str, object]:
    now = utc_now()
    plugin_runtime_paths_for_workspace = plugin_runtime_paths(root=paths["root"])
    runtime = {
        "tool_version": TOOL_VERSION,
        "schema_version": SCHEMA_VERSION,
        "requirements_version": REQUIREMENTS_VERSION,
        "template_source": TEMPLATE_SOURCE,
        "template_sha256": tool_sha256,
        "python_version": platform.python_version(),
        "generated_at": now,
        "last_verified_at": now,
        "plugin_runtime": describe_plugin_runtime(plugin_runtime_paths_for_workspace),
    }
    paths["runtime_path"].write_text(json.dumps(runtime, indent=2, sort_keys=True), encoding="utf-8")
    return runtime


def probe_fts5() -> dict[str, str]:
    connection = sqlite3.connect(":memory:")
    try:
        connection.execute("CREATE VIRTUAL TABLE t USING fts5(x)")
        return {"status": "pass", "detail": "FTS5 virtual table created successfully"}
    except Exception as exc:  # pragma: no cover - runtime probe
        return {"status": "fail", "detail": f"{type(exc).__name__}: {exc}"}
    finally:
        connection.close()


def detect_platform() -> dict[str, str]:
    return {
        "platform": platform.platform(),
        "system": platform.system(),
        "release": platform.release(),
        "machine": platform.machine(),
    }


def probe_processing_providers(connection: sqlite3.Connection | None) -> dict[str, object]:
    configured_providers: list[str] = []
    configured_capabilities: list[str] = []
    if connection is not None and table_exists(connection, "job_versions"):
        configured_providers = sorted(
            {
                normalize_whitespace(str(row["provider"] or "")).lower()
                for row in connection.execute(
                    """
                    SELECT DISTINCT provider
                    FROM job_versions
                    WHERE provider IS NOT NULL AND TRIM(provider) != ''
                    """
                ).fetchall()
                if normalize_whitespace(str(row["provider"] or ""))
            }
        )
        configured_capabilities = sorted(
            {
                normalize_whitespace(str(row["capability"] or "")).lower()
                for row in connection.execute(
                    """
                    SELECT DISTINCT capability
                    FROM job_versions
                    WHERE capability IS NOT NULL AND TRIM(capability) != ''
                    """
                ).fetchall()
                if normalize_whitespace(str(row["capability"] or ""))
            }
        )
    return {
        "configured_providers": configured_providers,
        "configured_capabilities": configured_capabilities,
        "cowork_runtime": {
            "status": "pass",
            "detail": "Cowork agent execution is the primary runtime path for processing jobs.",
        },
        "external_providers": {
            "status": "warn" if configured_providers else "pass",
            "detail": (
                "External provider identifiers are stored for future integrations, but are not required for Cowork execution."
                if configured_providers
                else "No external provider identifiers are configured."
            ),
        },
    }


def determine_workspace_state(paths: dict[str, Path]) -> str:
    state_dir = paths["state_dir"].exists()
    db_path = paths["db_path"].exists()
    db_usable = db_path and (file_size_bytes(paths["db_path"]) or 0) > 0
    runtime_path = paths["runtime_path"].exists()
    if all((state_dir, db_usable, runtime_path)):
        return "initialized"
    if any((state_dir, db_path, runtime_path)):
        return "partial"
    return "missing"


def workspace_status(root: Path, quick: bool) -> dict[str, object]:
    set_active_workspace_root(root)
    paths = workspace_paths(root)
    runtime_paths = plugin_runtime_paths(root=root)
    plugin_runtime = describe_plugin_runtime(runtime_paths)
    fts5 = probe_fts5()
    pip_python = (
        runtime_paths["venv_python_path"]
        if runtime_paths is not None and runtime_paths["venv_python_path"].exists()
        else Path(sys.executable)
    )
    pip_ok, pip_version = run_command([str(pip_python), "-m", "pip", "--version"])
    pst_backend = dependency_status(
        "pypff",
        package_name="libpff-python",
        import_name="pypff",
        detail_label="PST backend",
        probe_if_unloaded=True,
        allow_auto_install=False,
    )
    runtime = read_runtime(paths["runtime_path"])
    canonical_tool_path = locate_canonical_plugin_tool_or_self()
    current_sha = sha256_file(canonical_tool_path) if canonical_tool_path is not None else None
    stored_sha = None if runtime is None else runtime.get("template_sha256")
    workspace_state = determine_workspace_state(paths)
    registry_status = None
    workspace_inventory = None
    processing_providers = probe_processing_providers(None)
    journal_mode = None
    db_error = None
    workspace_meta = None
    actual_schema_version = None
    schema_needs_migration = None
    workspace_inventory_error = None
    registry_error = None

    if paths["db_path"].exists() and (file_size_bytes(paths["db_path"]) or 0) > 0:
        try:
            connection = connect_db(paths["db_path"])
            try:
                journal_mode = current_journal_mode(connection)
                workspace_meta = read_workspace_meta(connection)
                if workspace_meta is not None and workspace_meta.get("schema_version") is not None:
                    actual_schema_version = int(workspace_meta["schema_version"])
                    schema_needs_migration = actual_schema_version < SCHEMA_VERSION
                elif workspace_state != "missing":
                    schema_needs_migration = True

                if schema_needs_migration is not True:
                    if table_exists(connection, "documents"):
                        try:
                            workspace_inventory = document_inventory_counts(connection)
                        except Exception as exc:
                            workspace_inventory_error = f"{type(exc).__name__}: {exc}"
                    if table_exists(connection, "documents") and table_exists(connection, "custom_fields_registry"):
                        try:
                            registry_status = reconcile_custom_fields_registry(connection, repair=False)
                        except Exception as exc:
                            registry_error = f"{type(exc).__name__}: {exc}"

                processing_providers = probe_processing_providers(connection)
            finally:
                connection.close()
        except Exception as exc:
            db_error = f"{type(exc).__name__}: {exc}"

    overall = "pass"
    if fts5["status"] != "pass":
        overall = "fail"
    elif db_error is not None:
        overall = "fail"
    elif (
        workspace_state == "partial"
        or schema_needs_migration is True
        or workspace_inventory_error is not None
        or registry_error is not None
    ):
        overall = "partial"

    result: dict[str, object] = {
        "overall": overall,
        "tool_version": TOOL_VERSION,
        "schema_version": SCHEMA_VERSION,
        "workspace_schema_version": actual_schema_version,
        "schema_needs_migration": schema_needs_migration,
        "python_version": platform.python_version(),
        "pip_version": pip_version if pip_ok else None,
        "pip_status": "pass" if pip_ok else "fail",
        "sqlite_version": sqlite3.sqlite_version,
        "fts5": fts5,
        "pst_backend": pst_backend,
        "processing_providers": processing_providers,
        "platform": detect_platform(),
        "plugin_runtime": plugin_runtime,
        "workspace": {
            "root": str(root.resolve()),
            "state": workspace_state,
            "db_present": paths["db_path"].exists(),
            "db_size_bytes": file_size_bytes(paths["db_path"]),
            "runtime_present": paths["runtime_path"].exists(),
            "canonical_tool_present": canonical_tool_path is not None,
        },
        "tool_integrity": {
            "current_sha256": current_sha,
            "runtime_sha256": stored_sha,
            "matches_runtime": current_sha == stored_sha if current_sha and stored_sha else None,
        },
    }
    if journal_mode is not None:
        result["sqlite_journal_mode"] = journal_mode
    if db_error is not None:
        result["db_error"] = db_error
    if workspace_inventory is not None:
        result["workspace_inventory"] = workspace_inventory
    if workspace_inventory_error is not None:
        result["workspace_inventory_error"] = workspace_inventory_error
    if registry_error is not None:
        result["custom_field_registry_error"] = registry_error

    if not quick:
        result["paths"] = {key: str(value) for key, value in paths.items()}
        if runtime is not None:
            result["runtime"] = runtime
        if workspace_meta is not None:
            result["workspace_meta"] = workspace_meta
        if registry_status is not None:
            result["custom_field_registry"] = registry_status
    return result


def doctor(root: Path, quick: bool) -> dict[str, object]:
    set_active_workspace_root(root)
    paths = workspace_paths(root)
    runtime_paths = plugin_runtime_paths(root=root)
    plugin_runtime = describe_plugin_runtime(runtime_paths)
    fts5 = probe_fts5()
    pip_python = (
        runtime_paths["venv_python_path"]
        if runtime_paths is not None and runtime_paths["venv_python_path"].exists()
        else Path(sys.executable)
    )
    pip_ok, pip_version = run_command([str(pip_python), "-m", "pip", "--version"])
    pst_backend = dependency_status(
        "pypff",
        package_name="libpff-python",
        import_name="pypff",
        detail_label="PST backend",
        probe_if_unloaded=True,
        allow_auto_install=False,
    )
    runtime = read_runtime(paths["runtime_path"])
    canonical_tool_path = locate_canonical_plugin_tool_or_self()
    current_sha = sha256_file(canonical_tool_path) if canonical_tool_path is not None else None
    stored_sha = None if runtime is None else runtime.get("template_sha256")
    workspace_state = determine_workspace_state(paths)
    registry_status = None
    schema_status = None
    workspace_inventory = None
    processing_providers = probe_processing_providers(None)
    journal_mode = None
    db_error = None

    if paths["db_path"].exists():
        try:
            connection = connect_db(paths["db_path"])
            try:
                journal_mode = current_journal_mode(connection)
                schema_status = apply_schema(connection, root)
                registry_status = reconcile_custom_fields_registry(connection, repair=True)
                workspace_inventory = document_inventory_counts(connection)
                processing_providers = probe_processing_providers(connection)
            finally:
                connection.close()
        except Exception as exc:
            db_error = f"{type(exc).__name__}: {exc}"

    overall = "pass"
    if fts5["status"] != "pass":
        overall = "fail"
    elif db_error is not None:
        overall = "fail"
    elif workspace_state == "partial":
        overall = "partial"

    result: dict[str, object] = {
        "overall": overall,
        "tool_version": TOOL_VERSION,
        "schema_version": SCHEMA_VERSION,
        "python_version": platform.python_version(),
        "pip_version": pip_version if pip_ok else None,
        "pip_status": "pass" if pip_ok else "fail",
        "sqlite_version": sqlite3.sqlite_version,
        "fts5": fts5,
        "pst_backend": pst_backend,
        "processing_providers": processing_providers,
        "platform": detect_platform(),
        "plugin_runtime": plugin_runtime,
        "workspace": {
            "root": str(root.resolve()),
            "state": workspace_state,
            "db_present": paths["db_path"].exists(),
            "db_size_bytes": file_size_bytes(paths["db_path"]),
            "runtime_present": paths["runtime_path"].exists(),
            "canonical_tool_present": canonical_tool_path is not None,
        },
        "tool_integrity": {
            "current_sha256": current_sha,
            "runtime_sha256": stored_sha,
            "matches_runtime": current_sha == stored_sha if current_sha and stored_sha else None,
        },
    }
    if journal_mode is not None:
        result["sqlite_journal_mode"] = journal_mode
    if db_error is not None:
        result["db_error"] = db_error
    if workspace_inventory is not None:
        result["workspace_inventory"] = workspace_inventory

    if not quick:
        result["paths"] = {key: str(value) for key, value in paths.items()}
        if runtime is not None:
            result["runtime"] = runtime
        if schema_status is not None:
            result["schema_apply"] = schema_status
        if registry_status is not None:
            result["custom_field_registry"] = registry_status
    return result


def bootstrap(root: Path) -> dict[str, object]:
    set_active_workspace_root(root)
    paths = workspace_paths(root)
    ensure_layout(paths)
    canonical_tool_path = locate_canonical_plugin_tool_or_self()
    tool_sha = (
        sha256_file(canonical_tool_path)
        if canonical_tool_path is not None
        else sha256_file(Path(__file__).resolve())
    )
    recovered_sqlite_artifacts = remove_stale_sqlite_artifacts(paths["db_path"])
    last_error: Exception | None = None
    for attempt in range(2):
        try:
            connection = connect_db(paths["db_path"])
            try:
                journal_mode = current_journal_mode(connection)
                apply_schema(connection, root)
                registry_status = reconcile_custom_fields_registry(connection, repair=True)
                write_workspace_meta(connection, tool_sha)
            finally:
                connection.close()
            write_runtime(paths, tool_sha)
            result = {
                "status": "initialized" if paths["runtime_path"].exists() else "failed",
                "workspace_root": str(root.resolve()),
                "schema_version": SCHEMA_VERSION,
                "tool_version": TOOL_VERSION,
                "requirements_version": REQUIREMENTS_VERSION,
                "custom_field_registry": registry_status,
            }
            if journal_mode is not None:
                result["journal_mode"] = journal_mode
            if recovered_sqlite_artifacts:
                result["recovered_sqlite_artifacts"] = recovered_sqlite_artifacts
            return result
        except Exception as exc:
            last_error = exc
            if attempt == 0:
                retry_artifacts = remove_stale_sqlite_artifacts(paths["db_path"])
                if retry_artifacts:
                    for artifact in retry_artifacts:
                        if artifact not in recovered_sqlite_artifacts:
                            recovered_sqlite_artifacts.append(artifact)
                    continue
            break
    detail = f"{type(last_error).__name__}: {last_error}" if last_error is not None else "unknown bootstrap failure"
    if recovered_sqlite_artifacts:
        detail = (
            f"{detail}. Removed stale SQLite artifacts before retry: "
            f"{', '.join(recovered_sqlite_artifacts)}"
        )
    raise RetrieverError(f"Bootstrap failed for {paths['db_path']}: {detail}") from last_error


# Commands that must not trigger an auto-upgrade. `schema-version` needs to
# work even when a workspace does not exist yet. `workspace` owns the
# explicit init/status/update flows, so it should not transparently rewrite
# itself before dispatch. `slash` is intentionally not exempt so user-facing
# slash commands also benefit from clean-but-stale auto-upgrades.
AUTO_UPGRADE_EXEMPT_COMMANDS = frozenset(
    {
        "schema-version",
        "workspace",
    }
)


def locate_canonical_plugin_tool(current_file: str | None = None) -> Path | None:
    """Find the canonical ``skills/tool-template/tools.py`` bundle."""

    def _safe_resolve(path: Path) -> Path | None:
        try:
            return path.resolve()
        except OSError:
            return None

    env_path = os.environ.get("RETRIEVER_CANONICAL_TOOL_PATH")
    if env_path:
        candidate = Path(env_path).expanduser()
        if candidate.is_file():
            resolved = _safe_resolve(candidate)
            if resolved is not None:
                return resolved

    candidate_path = current_file or __file__
    try:
        start = Path(candidate_path).resolve()
    except OSError:
        start = None
    if start is None:
        return None

    sibling_candidate = start.with_name("tools.py")
    sibling_resolved = _safe_resolve(sibling_candidate)
    if sibling_resolved is not None and sibling_resolved.is_file():
        return sibling_resolved

    for parent in [start.parent, *start.parents]:
        candidate = parent / "skills" / "tool-template" / "tools.py"
        resolved = _safe_resolve(candidate)
        if resolved is not None and resolved.is_file():
            return resolved
    return None


def locate_canonical_plugin_tool_or_self(current_file: str | None = None) -> Path | None:
    located = locate_canonical_plugin_tool(current_file)
    if located is not None:
        return located

    candidate_path = current_file or __file__
    try:
        candidate = Path(candidate_path).resolve()
    except OSError:
        return None
    if (
        candidate.is_file()
        and candidate.parent.name == "tool-template"
        and candidate.parent.parent.name == "skills"
        and candidate.name == "tools.py"
    ):
        return candidate
    return None
    if (
        candidate.is_file()
        and candidate.parent.name == "tool-template"
        and candidate.parent.parent.name == "skills"
    ):
        return candidate
    return None


def upgrade_workspace_tool(
    root: Path,
    canonical_path: Path,
    *,
    force: bool = False,
    reason: str = "manual",
) -> dict[str, object]:
    """Refresh workspace runtime metadata from the canonical tool bundle."""
    del force
    paths = workspace_paths(root)
    ensure_layout(paths)
    runtime = read_runtime(paths["runtime_path"])
    runtime_sha = runtime.get("template_sha256") if isinstance(runtime, dict) else None
    runtime_version = runtime.get("tool_version") if isinstance(runtime, dict) else None
    canonical_sha = sha256_file(canonical_path)
    if canonical_sha is None:
        raise RetrieverError(f"Canonical tool not readable at {canonical_path}")

    write_runtime(paths, canonical_sha)

    meta_updated = False
    meta_error: str | None = None
    try:
        connection = connect_db(paths["db_path"])
        try:
            write_workspace_meta(connection, canonical_sha)
            meta_updated = True
        finally:
            connection.close()
    except Exception as exc:  # pragma: no cover - best-effort path
        meta_error = f"{type(exc).__name__}: {exc}"

    result: dict[str, object] = {
        "status": "no-op" if runtime_sha == canonical_sha else "updated-runtime",
        "reason": reason,
        "previous_tool_sha256": runtime_sha,
        "previous_tool_version": runtime_version,
        "new_tool_sha256": canonical_sha,
        "new_tool_version": TOOL_VERSION,
        "canonical_path": str(canonical_path),
        "workspace_meta_updated": meta_updated,
    }
    if meta_error is not None:
        result["workspace_meta_error"] = meta_error
    return result


def maybe_upgrade_workspace_tool(root: Path) -> dict[str, object] | None:
    """Best-effort runtime metadata refresh for a workspace."""
    paths = workspace_paths(root)
    if not paths["state_dir"].exists():
        return None
    runtime = read_runtime(paths["runtime_path"])
    if not isinstance(runtime, dict):
        return None

    canonical_path = locate_canonical_plugin_tool_or_self()
    if canonical_path is None:
        return None
    canonical_sha = sha256_file(canonical_path)
    if canonical_sha is None:
        return None
    if runtime.get("template_sha256") == canonical_sha and runtime.get("template_source") == TEMPLATE_SOURCE:
        return None
    return upgrade_workspace_tool(root, canonical_path, reason="auto-runtime-sync")


def init_workspace(root: Path, quick: bool = False) -> dict[str, object]:
    set_active_workspace_root(root)
    paths = workspace_paths(root)
    runtime_paths = plugin_runtime_paths(root=root)
    tool_update: dict[str, object] | None = None
    canonical_path = locate_canonical_plugin_tool_or_self()

    if canonical_path is not None:
        if not paths["runtime_path"].exists():
            tool_update = upgrade_workspace_tool(
                root,
                canonical_path,
                force=False,
                reason="workspace-init",
            )
        else:
            maybe_update = maybe_upgrade_workspace_tool(root)
            if maybe_update is not None:
                tool_update = maybe_update

    runtime_init = ensure_plugin_runtime(
        runtime_paths,
        install_requirements=True,
        force_requirements_install=False,
        reason="init",
    )
    initialization_payload = bootstrap(root)
    result: dict[str, object] = {
        "action": "init",
        "status": "ready",
        "workspace_root": str(root.resolve()),
        "initialization": initialization_payload,
        "status_report": workspace_status(root, quick=quick),
    }
    if tool_update is not None:
        result["tool_update"] = tool_update
    if payload_has_meaningful_value(runtime_init):
        result["runtime_init"] = runtime_init
    return result


def write_workspace_meta(connection: sqlite3.Connection, tool_sha256: str | None) -> None:
    now = utc_now()
    connection.execute(
        """
        INSERT INTO workspace_meta (
          id, schema_version, tool_version, requirements_version,
          template_source, template_sha256, created_at, updated_at
        ) VALUES (1, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(id) DO UPDATE SET
          schema_version = excluded.schema_version,
          tool_version = excluded.tool_version,
          requirements_version = excluded.requirements_version,
          template_source = excluded.template_source,
          template_sha256 = excluded.template_sha256,
          updated_at = excluded.updated_at
        """,
        (
            SCHEMA_VERSION,
            TOOL_VERSION,
            REQUIREMENTS_VERSION,
            TEMPLATE_SOURCE,
            tool_sha256,
            now,
            now,
        ),
    )
    connection.commit()


def resolve_production_root_argument(workspace_root: Path, raw_production_root: str | Path) -> Path:
    candidate = Path(raw_production_root).expanduser()
    if not candidate.is_absolute():
        candidate = workspace_root / candidate
    candidate = candidate.resolve()
    try:
        candidate.relative_to(workspace_root.resolve())
    except ValueError as exc:
        raise RetrieverError("Production root must be inside the workspace root for Phase 4 ingest.") from exc
    return candidate


def production_row_signature(
    existing_row: sqlite3.Row | None,
    *,
    rel_path: str,
    file_name: str,
    source_kind: str,
    production_id: int,
    begin_bates: str,
    end_bates: str,
    begin_attachment: str | None,
    end_attachment: str | None,
    extracted: dict[str, object],
    source_parts: list[dict[str, object]],
) -> tuple[object, ...]:
    existing_locks = existing_row[MANUAL_FIELD_LOCKS_COLUMN] if existing_row is not None else "[]"
    return (
        rel_path,
        file_name,
        source_kind,
        production_id,
        begin_bates,
        end_bates,
        begin_attachment,
        end_attachment,
        extracted.get("title"),
        extracted.get("content_type"),
        extracted.get("text_status"),
        sha256_text(str(extracted.get("text_content") or "")),
        extracted.get("page_count"),
        tuple((part["part_kind"], part["rel_source_path"], int(part.get("ordinal", 0))) for part in source_parts),
        bool(extracted.get("preview_artifacts")),
        existing_locks,
    )


def existing_production_row_signature(connection: sqlite3.Connection, row: sqlite3.Row | None) -> tuple[object, ...] | None:
    if row is None:
        return None
    source_parts = connection.execute(
        """
        SELECT part_kind, rel_source_path, ordinal
        FROM document_source_parts
        WHERE document_id = ?
        ORDER BY part_kind ASC, ordinal ASC, id ASC
        """,
        (row["id"],),
    ).fetchall()
    return (
        row["rel_path"],
        row["file_name"],
        row["source_kind"],
        row["production_id"],
        row["begin_bates"],
        row["end_bates"],
        row["begin_attachment"],
        row["end_attachment"],
        row["title"],
        row["content_type"],
        row["text_status"],
        row["content_hash"],
        row["page_count"],
        tuple((part["part_kind"], part["rel_source_path"], int(part["ordinal"])) for part in source_parts),
        connection.execute("SELECT COUNT(*) AS count FROM document_previews WHERE document_id = ?", (row["id"],)).fetchone()["count"] > 0,
        row[MANUAL_FIELD_LOCKS_COLUMN],
    )
