def claim_run_item_rows(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    claimed_by: str,
    limit: int,
    stale_after_seconds: int = DEFAULT_RUN_ITEM_CLAIM_STALE_SECONDS,
) -> list[sqlite3.Row]:
    normalized_claimed_by = normalize_whitespace(claimed_by)
    if not normalized_claimed_by:
        raise RetrieverError("claimed_by cannot be empty.")
    if limit < 1:
        return []
    run_row = require_run_row_by_id(connection, run_id)
    if str(run_row["status"] or "") in {"canceled", "completed", "failed"}:
        return []

    stale_cutoff = format_utc_timestamp(datetime.now(timezone.utc) - timedelta(seconds=max(1, stale_after_seconds)))
    stale_claimed_rows = connection.execute(
        """
        SELECT DISTINCT claimed_by
        FROM run_items
        WHERE run_id = ?
          AND status = 'running'
          AND result_id IS NULL
          AND claimed_by IS NOT NULL
          AND last_heartbeat_at IS NOT NULL
          AND last_heartbeat_at < ?
        """,
        (run_id, stale_cutoff),
    ).fetchall()
    for stale_row in stale_claimed_rows:
        stale_claimed_by = normalize_whitespace(str(stale_row["claimed_by"] or ""))
        if not stale_claimed_by or stale_claimed_by == normalized_claimed_by:
            continue
        update_run_worker_row(
            connection,
            run_id=run_id,
            claimed_by=stale_claimed_by,
            status="orphaned",
            last_error="Worker claim heartbeat expired and items were reclaimed.",
            completed_at=utc_now(),
        )

    candidate_rows = connection.execute(
        """
        SELECT *
        FROM run_items
        WHERE run_id = ?
          AND (
            status = 'pending'
            OR (
              status = 'running'
              AND result_id IS NULL
              AND claimed_by IS NOT NULL
              AND last_heartbeat_at IS NOT NULL
              AND last_heartbeat_at < ?
            )
          )
        ORDER BY id ASC
        LIMIT ?
        """,
        (run_id, stale_cutoff, limit),
    ).fetchall()
    if not candidate_rows:
        return []

    now = utc_now()
    item_ids = [int(row["id"]) for row in candidate_rows]
    placeholders = ", ".join("?" for _ in item_ids)
    connection.execute(
        f"""
        UPDATE run_items
        SET status = 'running',
            claimed_by = ?,
            claimed_at = ?,
            last_heartbeat_at = ?,
            started_at = COALESCE(started_at, ?),
            completed_at = NULL
        WHERE id IN ({placeholders})
        """,
        (normalized_claimed_by, now, now, now, *item_ids),
    )
    connection.execute(
        """
        UPDATE runs
        SET status = 'running',
            started_at = COALESCE(started_at, ?),
            completed_at = NULL,
            canceled_at = NULL
        WHERE id = ?
        """,
        (now, run_id),
    )
    return connection.execute(
        f"""
        SELECT *
        FROM run_items
        WHERE id IN ({placeholders})
        ORDER BY id ASC
        """,
        item_ids,
    ).fetchall()


def heartbeat_claimed_run_items(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    claimed_by: str,
) -> int:
    normalized_claimed_by = normalize_whitespace(claimed_by)
    if not normalized_claimed_by:
        raise RetrieverError("claimed_by cannot be empty.")
    now = utc_now()
    cursor = connection.execute(
        """
        UPDATE run_items
        SET last_heartbeat_at = ?
        WHERE run_id = ?
          AND status = 'running'
          AND claimed_by = ?
        """,
        (now, run_id, normalized_claimed_by),
    )
    update_run_worker_row(
        connection,
        run_id=run_id,
        claimed_by=normalized_claimed_by,
        heartbeat=True,
    )
    return int(cursor.rowcount or 0)


def cancel_pending_run_items(connection: sqlite3.Connection, *, run_id: int) -> int:
    now = utc_now()
    cursor = connection.execute(
        """
        UPDATE run_items
        SET status = 'skipped',
            last_error = COALESCE(last_error, 'Run canceled.'),
            completed_at = COALESCE(completed_at, ?)
        WHERE run_id = ?
          AND status = 'pending'
        """,
        (now, run_id),
    )
    return int(cursor.rowcount or 0)


def request_run_worker_cancellation(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    force: bool,
) -> list[str]:
    worker_rows = connection.execute(
        """
        SELECT claimed_by, worker_task_id
        FROM run_workers
        WHERE run_id = ?
          AND status = 'active'
        ORDER BY claimed_by ASC
        """,
        (run_id,),
    ).fetchall()
    task_ids: list[str] = []
    for row in worker_rows:
        claimed_by = normalize_whitespace(str(row["claimed_by"] or ""))
        worker_task_id = normalize_whitespace(str(row["worker_task_id"] or "")) or None
        if worker_task_id:
            task_ids.append(worker_task_id)
        update_run_worker_row(
            connection,
            run_id=run_id,
            claimed_by=claimed_by,
            status="canceled",
            cancel_requested=True,
            last_error=("Force-stop requested." if force else "Cancellation requested."),
            completed_at=utc_now() if force else None,
        )
    return task_ids


def run_item_status_counts(connection: sqlite3.Connection, run_id: int) -> dict[str, int]:
    return {
        str(row["status"]): int(row["count"] or 0)
        for row in connection.execute(
            """
            SELECT status, COUNT(*) AS count
            FROM run_items
            WHERE run_id = ?
            GROUP BY status
            """,
            (run_id,),
        ).fetchall()
    }


def run_execution_metadata(connection: sqlite3.Connection, run_id: int) -> tuple[sqlite3.Row, sqlite3.Row, sqlite3.Row]:
    run_row = require_run_row_by_id(connection, run_id)
    job_version_row = require_job_version_row_by_id(connection, int(run_row["job_version_id"]))
    job_row = connection.execute(
        """
        SELECT *
        FROM jobs
        WHERE id = ?
        """,
        (job_version_row["job_id"],),
    ).fetchone()
    if job_row is None:
        raise RetrieverError(f"Run {run_id} references a missing job id: {job_version_row['job_id']}")
    return run_row, job_version_row, job_row


def ocr_run_pending_finalization_count(connection: sqlite3.Connection, run_id: int) -> int:
    row = connection.execute(
        """
        SELECT COUNT(*) AS count
        FROM run_snapshot_documents AS snapshot
        WHERE snapshot.run_id = ?
          AND EXISTS (
            SELECT 1
            FROM run_items AS page_item
            WHERE page_item.run_id = snapshot.run_id
              AND page_item.document_id = snapshot.document_id
              AND page_item.item_kind = 'page'
          )
          AND NOT EXISTS (
            SELECT 1
            FROM run_items AS finalized_item
            WHERE finalized_item.run_id = snapshot.run_id
              AND finalized_item.document_id = snapshot.document_id
              AND finalized_item.result_id IS NOT NULL
          )
        """,
        (run_id,),
    ).fetchone()
    return int(row["count"] or 0)


def image_description_run_pending_finalization_count(connection: sqlite3.Connection, run_id: int) -> int:
    row = connection.execute(
        """
        SELECT COUNT(*) AS count
        FROM run_snapshot_documents AS snapshot
        WHERE snapshot.run_id = ?
          AND EXISTS (
            SELECT 1
            FROM run_items AS page_item
            WHERE page_item.run_id = snapshot.run_id
              AND page_item.document_id = snapshot.document_id
              AND page_item.item_kind = 'page'
          )
          AND NOT EXISTS (
            SELECT 1
            FROM run_items AS finalized_item
            WHERE finalized_item.run_id = snapshot.run_id
              AND finalized_item.document_id = snapshot.document_id
              AND finalized_item.result_id IS NOT NULL
          )
        """,
        (run_id,),
    ).fetchone()
    return int(row["count"] or 0)


def build_run_worker_payload(
    connection: sqlite3.Connection,
    run_id: int,
    *,
    run_payload: dict[str, object],
    claimed_by: str | None = None,
) -> dict[str, object]:
    _, job_version_row, job_row = run_execution_metadata(connection, run_id)
    job_kind = normalize_job_kind(str(job_row["job_kind"]))
    capability = normalize_job_capability(str(job_version_row["capability"]))
    run_item_counts = dict(run_payload.get("run_item_counts") or {})
    pending_count = int(run_item_counts.get("pending", 0) or 0)
    running_count = int(run_item_counts.get("running", 0) or 0)
    completed_count = int(run_item_counts.get("completed", 0) or 0)
    failed_count = int(run_item_counts.get("failed", 0) or 0)
    skipped_count = int(run_item_counts.get("skipped", 0) or 0)
    planned_count = int(run_payload.get("planned_count", 0) or 0)
    total_items = pending_count + running_count + completed_count + failed_count + skipped_count
    outstanding_items = max(planned_count - completed_count - failed_count - skipped_count, 0)
    needs_ocr_finalization = job_kind == "ocr" and ocr_run_pending_finalization_count(connection, run_id) > 0
    needs_image_description_finalization = (
        job_kind == "image_description" and image_description_run_pending_finalization_count(connection, run_id) > 0
    )
    normalized_claimed_by = normalize_whitespace(claimed_by) if claimed_by and claimed_by.strip() else None
    worker_row = (
        find_run_worker_row(connection, run_id=run_id, claimed_by=normalized_claimed_by)
        if normalized_claimed_by
        else None
    )
    recommended_execution_mode = (
        "background"
        if max(total_items, planned_count) > DEFAULT_WORKER_INLINE_MAX_ITEMS
        else "inline"
    )
    recommended_batch_size = min(
        DEFAULT_RUN_ITEM_CLAIM_BATCH_SIZE,
        DEFAULT_WORKER_BATCH_SIZE,
        max(outstanding_items, 1),
    )
    recommended_max_batches = (
        DEFAULT_WORKER_BACKGROUND_MAX_BATCHES
        if recommended_execution_mode == "background"
        else DEFAULT_WORKER_INLINE_MAX_BATCHES
    )
    effective_max_batches = (
        int(worker_row["max_batches"])
        if worker_row is not None and worker_row["max_batches"] is not None
        else recommended_max_batches
    )
    worker_batches_prepared = int(worker_row["batches_prepared"] or 0) if worker_row is not None else 0
    worker_cancel_requested = worker_row is not None and worker_row["cancel_requested_at"] is not None
    worker_should_handoff = (
        worker_row is not None
        and effective_max_batches > 0
        and worker_batches_prepared >= effective_max_batches
        and pending_count > 0
    )

    next_action = "claim"
    stop_reason = None
    run_status = str(run_payload.get("status") or "")
    if run_status == "canceled":
        next_action = "stop"
        stop_reason = "canceled"
    elif worker_cancel_requested:
        next_action = "stop"
        stop_reason = "canceled"
    elif worker_should_handoff:
        next_action = "handoff"
        stop_reason = "max_batches_reached"
    elif needs_ocr_finalization and pending_count == 0 and running_count == 0 and failed_count == 0:
        next_action = "finalize_ocr"
    elif needs_image_description_finalization and pending_count == 0 and running_count == 0 and failed_count == 0:
        next_action = "finalize_image_description"
    elif planned_count == 0:
        next_action = "stop"
        stop_reason = "empty"
    elif outstanding_items == 0 and pending_count == 0 and running_count == 0:
        next_action = "stop"
        if failed_count:
            stop_reason = "failed"
        elif run_status == "completed":
            stop_reason = "completed"
        else:
            stop_reason = run_status or "idle"

    return {
        "job_kind": job_kind,
        "capability": capability,
        "claimed_by": normalized_claimed_by,
        "launch_mode": worker_row["launch_mode"] if worker_row is not None else None,
        "worker_task_id": worker_row["worker_task_id"] if worker_row is not None else None,
        "worker_status": worker_row["status"] if worker_row is not None else None,
        "recommended_execution_mode": recommended_execution_mode,
        "recommended_batch_size": recommended_batch_size,
        "recommended_max_batches_per_worker": recommended_max_batches,
        "max_batches_per_worker": effective_max_batches,
        "batches_prepared": worker_batches_prepared,
        "outstanding_items": outstanding_items,
        "needs_ocr_finalization": needs_ocr_finalization,
        "needs_image_description_finalization": needs_image_description_finalization,
        "should_exit_after_batch": worker_should_handoff,
        "after_batch_action": "handoff" if worker_should_handoff else None,
        "next_action": next_action,
        "stop_reason": stop_reason,
    }


def recent_run_item_failures(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    limit: int = 10,
) -> list[dict[str, object]]:
    rows = connection.execute(
        """
        SELECT id, document_id, segment_id, last_error, completed_at
        FROM run_items
        WHERE run_id = ?
          AND status = 'failed'
        ORDER BY completed_at DESC, id DESC
        LIMIT ?
        """,
        (run_id, max(1, limit)),
    ).fetchall()
    return [
        {
            "run_item_id": int(row["id"]),
            "document_id": int(row["document_id"]),
            "segment_id": row["segment_id"],
            "error": row["last_error"],
            "completed_at": row["completed_at"],
        }
        for row in rows
    ]


def build_run_supervision_payload(
    connection: sqlite3.Connection,
    run_id: int,
    *,
    run_payload: dict[str, object],
    worker_payloads: list[dict[str, object]],
) -> dict[str, object]:
    run_status = str(run_payload.get("status") or "")
    run_worker_hint = build_run_worker_payload(connection, run_id, run_payload=run_payload)
    active_workers = [payload for payload in worker_payloads if str(payload["status"]) == "active"]
    background_workers = [payload for payload in active_workers if str(payload["launch_mode"]) == "background"]
    orphaned_workers = [payload for payload in worker_payloads if str(payload["status"]) == "orphaned"]
    max_parallel_workers = DEFAULT_WORKER_BACKGROUND_MAX_PARALLEL
    outstanding_items = int(run_worker_hint["outstanding_items"] or 0)
    finalization_pending = bool(
        run_worker_hint["needs_ocr_finalization"] or run_worker_hint["needs_image_description_finalization"]
    )
    if run_worker_hint["recommended_execution_mode"] == "background" and outstanding_items > 0:
        suggested_worker_count = min(
            max_parallel_workers,
            max(1, (outstanding_items + DEFAULT_WORKER_BATCH_SIZE - 1) // DEFAULT_WORKER_BATCH_SIZE),
        )
    elif outstanding_items > 0:
        suggested_worker_count = 1
    else:
        suggested_worker_count = 0
    spawn_additional_worker_count = max(0, suggested_worker_count - len(active_workers))
    force_stop_task_ids = [
        str(payload["worker_task_id"])
        for payload in worker_payloads
        if payload["cancel_requested_at"] is not None and payload["worker_task_id"]
    ]
    should_schedule_wakeup = bool(
        run_status not in {"canceled", "completed", "failed"}
        and (outstanding_items > 0 or len(active_workers) > 0 or finalization_pending)
    )
    if run_status in {"canceled", "completed", "failed"}:
        wakeup_reason = None
    elif finalization_pending and not active_workers:
        wakeup_reason = "finalization_pending"
    elif len(active_workers) > 0:
        wakeup_reason = "workers_active"
    elif outstanding_items > 0:
        wakeup_reason = "pending_work"
    else:
        wakeup_reason = None

    recommended_action = "wait"
    if run_status == "canceled":
        recommended_action = "stop"
    elif run_worker_hint["next_action"] in {"finalize_ocr", "finalize_image_description"}:
        recommended_action = str(run_worker_hint["next_action"])
    elif run_worker_hint["next_action"] == "stop":
        recommended_action = "stop"
    elif spawn_additional_worker_count > 0:
        recommended_action = "spawn_background_worker" if run_worker_hint["recommended_execution_mode"] == "background" else "claim_inline"

    return {
        "active_worker_count": len(active_workers),
        "background_worker_count": len(background_workers),
        "orphaned_worker_count": len(orphaned_workers),
        "continuation_needed": bool(outstanding_items and not active_workers and run_status not in {"canceled", "completed", "failed"}),
        "outstanding_items": outstanding_items,
        "finalization_pending": finalization_pending,
        "max_parallel_workers": max_parallel_workers,
        "suggested_worker_count": suggested_worker_count,
        "spawn_additional_worker_count": spawn_additional_worker_count,
        "should_schedule_wakeup": should_schedule_wakeup,
        "wake_interval_seconds": (DEFAULT_WORKER_BACKGROUND_WAKE_INTERVAL_SECONDS if should_schedule_wakeup else None),
        "wakeup_reason": wakeup_reason,
        "force_stop_task_ids": force_stop_task_ids,
        "recommended_action": recommended_action,
    }


def attempt_row_to_payload(row: sqlite3.Row) -> dict[str, object]:
    return {
        "id": int(row["id"]),
        "run_item_id": int(row["run_item_id"]),
        "attempt_number": int(row["attempt_number"]),
        "provider_request_id": row["provider_request_id"],
        "input_tokens": row["input_tokens"],
        "output_tokens": row["output_tokens"],
        "cost_cents": row["cost_cents"],
        "latency_ms": row["latency_ms"],
        "provider_metadata": decode_json_text(row["provider_metadata_json"], default={}) or {},
        "error_summary": row["error_summary"],
        "created_at": row["created_at"],
    }


def next_attempt_number_for_run_item(connection: sqlite3.Connection, run_item_id: int) -> int:
    row = connection.execute(
        """
        SELECT COALESCE(MAX(attempt_number), 0) AS max_attempt_number
        FROM attempts
        WHERE run_item_id = ?
        """,
        (run_item_id,),
    ).fetchone()
    return int(row["max_attempt_number"] or 0) + 1


def create_attempt_row(
    connection: sqlite3.Connection,
    *,
    run_item_id: int,
    provider_request_id: str | None,
    input_tokens: int | None,
    output_tokens: int | None,
    cost_cents: int | None,
    latency_ms: int | None,
    provider_metadata: dict[str, object] | None,
    error_summary: str | None,
) -> int:
    attempt_number = next_attempt_number_for_run_item(connection, run_item_id)
    cursor = connection.execute(
        """
        INSERT INTO attempts (
          run_item_id,
          attempt_number,
          provider_request_id,
          input_tokens,
          output_tokens,
          cost_cents,
          latency_ms,
          provider_metadata_json,
          error_summary,
          created_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            run_item_id,
            attempt_number,
            provider_request_id,
            input_tokens,
            output_tokens,
            cost_cents,
            latency_ms,
            compact_json_text(provider_metadata or {}),
            error_summary,
            utc_now(),
        ),
    )
    return int(cursor.lastrowid)


def result_row_to_payload(row: sqlite3.Row) -> dict[str, object]:
    return {
        "id": int(row["id"]),
        "run_id": row["run_id"],
        "document_id": int(row["document_id"]),
        "job_version_id": int(row["job_version_id"]),
        "input_revision_id": row["input_revision_id"],
        "input_identity": row["input_identity"],
        "raw_output": decode_json_text(row["raw_output_json"]),
        "normalized_output": decode_json_text(row["normalized_output_json"]),
        "created_text_revision_id": row["created_text_revision_id"],
        "provider_metadata": decode_json_text(row["provider_metadata_json"], default={}) or {},
        "created_at": row["created_at"],
        "retracted_at": row["retracted_at"],
        "retraction_reason": row["retraction_reason"],
    }


def find_active_result_row(
    connection: sqlite3.Connection,
    *,
    document_id: int,
    job_version_id: int,
    input_identity: str,
) -> sqlite3.Row | None:
    return connection.execute(
        """
        SELECT *
        FROM results
        WHERE document_id = ?
          AND job_version_id = ?
          AND input_identity = ?
          AND retracted_at IS NULL
        ORDER BY id DESC
        LIMIT 1
        """,
        (document_id, job_version_id, input_identity),
    ).fetchone()


def create_result_row(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    document_id: int,
    job_version_id: int,
    input_revision_id: int | None,
    input_identity: str,
    raw_output: object,
    normalized_output: object,
    created_text_revision_id: int | None,
    provider_metadata: dict[str, object] | None,
) -> tuple[int, bool]:
    existing_row = find_active_result_row(
        connection,
        document_id=document_id,
        job_version_id=job_version_id,
        input_identity=input_identity,
    )
    if existing_row is not None:
        return int(existing_row["id"]), False

    now = utc_now()
    try:
        cursor = connection.execute(
            """
            INSERT INTO results (
              run_id,
              document_id,
              job_version_id,
              input_revision_id,
              input_identity,
              raw_output_json,
              normalized_output_json,
              created_text_revision_id,
              provider_metadata_json,
              created_at,
              retracted_at,
              retraction_reason
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NULL, NULL)
            """,
            (
                run_id,
                document_id,
                job_version_id,
                input_revision_id,
                input_identity,
                compact_json_text(raw_output),
                compact_json_text(normalized_output),
                created_text_revision_id,
                compact_json_text(provider_metadata or {}),
                now,
            ),
        )
        return int(cursor.lastrowid), True
    except sqlite3.IntegrityError:
        existing_row = find_active_result_row(
            connection,
            document_id=document_id,
            job_version_id=job_version_id,
            input_identity=input_identity,
        )
        if existing_row is None:
            raise
        return int(existing_row["id"]), False


def result_output_display_value(output_value: object) -> str | None:
    if output_value is None:
        return None
    if isinstance(output_value, bool):
        return "true" if output_value else "false"
    if isinstance(output_value, (int, float)):
        return str(output_value)
    if isinstance(output_value, str):
        return output_value
    return compact_json_text(output_value)


def upsert_result_output_rows(
    connection: sqlite3.Connection,
    *,
    result_id: int,
    job_output_rows: list[sqlite3.Row],
    output_values_by_name: dict[str, object],
) -> None:
    now = utc_now()
    for job_output_row in job_output_rows:
        output_name = str(job_output_row["output_name"])
        output_value = output_values_by_name.get(output_name)
        connection.execute(
            """
            INSERT INTO result_outputs (
              result_id,
              job_output_id,
              output_value_json,
              display_value,
              score,
              created_at
            ) VALUES (?, ?, ?, ?, ?, ?)
            ON CONFLICT(result_id, job_output_id) DO NOTHING
            """,
            (
                result_id,
                int(job_output_row["id"]),
                compact_json_text(output_value),
                result_output_display_value(output_value),
                None,
                now,
            ),
        )


def result_output_row_to_payload(row: sqlite3.Row) -> dict[str, object]:
    return {
        "id": int(row["id"]),
        "result_id": int(row["result_id"]),
        "job_output_id": int(row["job_output_id"]),
        "output_name": row["output_name"],
        "value_type": row["value_type"],
        "bound_custom_field": row["bound_custom_field"],
        "output_value": decode_json_text(row["output_value_json"]),
        "display_value": row["display_value"],
        "score": row["score"],
        "created_at": row["created_at"],
    }


def result_outputs_for_result(connection: sqlite3.Connection, result_id: int) -> list[dict[str, object]]:
    rows = connection.execute(
        """
        SELECT ro.*, jo.output_name, jo.value_type, jo.bound_custom_field
        FROM result_outputs ro
        JOIN job_outputs jo ON jo.id = ro.job_output_id
        WHERE ro.result_id = ?
        ORDER BY jo.ordinal ASC, jo.output_name ASC, ro.id ASC
        """,
        (result_id,),
    ).fetchall()
    return [result_output_row_to_payload(row) for row in rows]


def result_summary_by_id(connection: sqlite3.Connection, result_id: int) -> dict[str, object]:
    row = connection.execute(
        """
        SELECT *
        FROM results
        WHERE id = ?
        """,
        (result_id,),
    ).fetchone()
    if row is None:
        raise RetrieverError(f"Unknown result id: {result_id}")
    payload = result_row_to_payload(row)
    payload["outputs"] = result_outputs_for_result(connection, result_id)
    return payload


def list_result_summaries(
    connection: sqlite3.Connection,
    *,
    run_id: int | None = None,
    document_id: int | None = None,
) -> list[dict[str, object]]:
    if run_id is not None:
        rows = connection.execute(
            """
            SELECT DISTINCT r.*
            FROM run_items ri
            JOIN results r ON r.id = ri.result_id
            WHERE ri.run_id = ?
            ORDER BY r.id DESC
            """,
            (run_id,),
        ).fetchall()
        if document_id is not None:
            rows = [row for row in rows if int(row["document_id"]) == int(document_id)]
        return [result_summary_by_id(connection, int(row["id"])) for row in rows]

    if document_id is None:
        rows = connection.execute(
            """
            SELECT *
            FROM results
            ORDER BY id DESC
            """
        ).fetchall()
    else:
        rows = connection.execute(
            """
            SELECT *
            FROM results
            WHERE document_id = ?
            ORDER BY id DESC
            """,
            (document_id,),
        ).fetchall()
    return [result_summary_by_id(connection, int(row["id"])) for row in rows]


def refresh_run_progress(connection: sqlite3.Connection, run_id: int) -> None:
    snapshot_count = int(
        connection.execute(
            """
            SELECT COUNT(*) AS count
            FROM run_snapshot_documents
            WHERE run_id = ?
            """,
            (run_id,),
        ).fetchone()["count"]
        or 0
    )
    run_item_total = int(
        connection.execute(
            """
            SELECT COUNT(*) AS count
            FROM run_items
            WHERE run_id = ?
            """,
            (run_id,),
        ).fetchone()["count"]
        or 0
    )
    planned_count = run_item_total or snapshot_count
    counts = {
        str(row["status"]): int(row["count"] or 0)
        for row in connection.execute(
            """
            SELECT status, COUNT(*) AS count
            FROM run_items
            WHERE run_id = ?
            GROUP BY status
            """,
            (run_id,),
        ).fetchall()
    }
    completed_count = counts.get("completed", 0)
    failed_count = counts.get("failed", 0)
    skipped_count = counts.get("skipped", 0)
    running_count = counts.get("running", 0)
    pending_count = counts.get("pending", 0)
    row = connection.execute(
        """
        SELECT started_at, canceled_at
        FROM runs
        WHERE id = ?
        """,
        (run_id,),
    ).fetchone()
    if row is None:
        raise RetrieverError(f"Unknown run id: {run_id}")
    if row["canceled_at"] is not None:
        status = "canceled"
    elif planned_count == 0:
        status = "completed"
    elif completed_count + failed_count + skipped_count >= planned_count and pending_count == 0 and running_count == 0:
        status = "failed" if failed_count else "completed"
    elif running_count > 0:
        status = "running"
    else:
        status = "planned"
    started_at = row["started_at"] or (utc_now() if status in {"running", "completed", "failed"} else None)
    completed_at = utc_now() if status in {"completed", "failed", "canceled"} else None
    connection.execute(
        """
        UPDATE runs
        SET status = ?,
            planned_count = ?,
            completed_count = ?,
            failed_count = ?,
            skipped_count = ?,
            started_at = ?,
            completed_at = ?
        WHERE id = ?
        """,
        (
            status,
            planned_count,
            completed_count,
            failed_count,
            skipped_count,
            started_at,
            completed_at,
            run_id,
        ),
    )


def run_status_by_id(connection: sqlite3.Connection, run_id: int) -> dict[str, object]:
    refresh_run_progress(connection, run_id)
    payload = run_summary_by_id(connection, run_id)
    status_counts = run_item_status_counts(connection, run_id)
    payload["run_item_counts"] = {
        "pending": status_counts.get("pending", 0),
        "running": status_counts.get("running", 0),
        "completed": status_counts.get("completed", 0),
        "failed": status_counts.get("failed", 0),
        "skipped": status_counts.get("skipped", 0),
    }
    payload["snapshot_document_count"] = len(payload.get("documents", []))
    payload["recent_failures"] = recent_run_item_failures(connection, run_id=run_id)
    active_claim_rows = connection.execute(
        """
        SELECT claimed_by, COUNT(*) AS count, MAX(last_heartbeat_at) AS last_heartbeat_at
        FROM run_items
        WHERE run_id = ?
          AND status = 'running'
          AND claimed_by IS NOT NULL
        GROUP BY claimed_by
        ORDER BY claimed_by ASC
        """,
        (run_id,),
    ).fetchall()
    payload["active_claims"] = [
        {
            "claimed_by": row["claimed_by"],
            "count": int(row["count"] or 0),
            "last_heartbeat_at": row["last_heartbeat_at"],
        }
        for row in active_claim_rows
    ]
    payload["workers"] = list_run_worker_payloads_for_run(connection, run_id)
    payload["worker"] = build_run_worker_payload(connection, run_id, run_payload=payload)
    payload["supervision"] = build_run_supervision_payload(
        connection,
        run_id,
        run_payload=payload,
        worker_payloads=payload["workers"],
    )
    return payload


def finalize_ocr_results_for_run(
    connection: sqlite3.Connection,
    paths: dict[str, Path],
    *,
    run_id: int,
) -> dict[str, object]:
    run_row = require_run_row_by_id(connection, run_id)
    job_version_row = require_job_version_row_by_id(connection, int(run_row["job_version_id"]))
    job_row = connection.execute(
        """
        SELECT *
        FROM jobs
        WHERE id = ?
        """,
        (job_version_row["job_id"],),
    ).fetchone()
    assert job_row is not None
    if normalize_job_kind(str(job_row["job_kind"])) != "ocr":
        raise RetrieverError("finalize-ocr-run only supports OCR jobs.")

    pending_counts = run_item_status_counts(connection, run_id)
    if pending_counts.get("pending", 0) or pending_counts.get("running", 0) or pending_counts.get("failed", 0):
        raise RetrieverError(
            "OCR run cannot be finalized until all page items are completed. "
            f"pending={pending_counts.get('pending', 0)}, "
            f"running={pending_counts.get('running', 0)}, "
            f"failed={pending_counts.get('failed', 0)}."
        )

    snapshot_rows = connection.execute(
        """
        SELECT *
        FROM run_snapshot_documents
        WHERE run_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (run_id,),
    ).fetchall()
    finalized_results: list[dict[str, object]] = []
    activations: list[dict[str, object]] = []
    for snapshot_row in snapshot_rows:
        document_id = int(snapshot_row["document_id"])
        existing_result_row = find_active_result_row(
            connection,
            document_id=document_id,
            job_version_id=int(job_version_row["id"]),
            input_identity=str(snapshot_row["pinned_input_identity"]),
        )
        if existing_result_row is not None and existing_result_row["created_text_revision_id"] is not None:
            result_id = int(existing_result_row["id"])
            connection.execute(
                """
                UPDATE run_items
                SET result_id = ?
                WHERE run_id = ?
                  AND document_id = ?
                """,
                (result_id, run_id, document_id),
            )
            activation_payload = maybe_activate_created_text_revision(
                connection,
                paths,
                run_row=run_row,
                job_version_row=job_version_row,
                document_id=document_id,
                result_id=result_id,
                text_revision_id=int(existing_result_row["created_text_revision_id"]),
            )
            if activation_payload is not None:
                activations.append(activation_payload)
            finalized_results.append(result_summary_by_id(connection, result_id))
            continue

        page_rows = connection.execute(
            """
            SELECT *
            FROM run_items
            WHERE run_id = ?
              AND document_id = ?
              AND item_kind = 'page'
            ORDER BY page_number ASC, id ASC
            """,
            (run_id, document_id),
        ).fetchall()
        if not page_rows:
            raise RetrieverError(f"OCR run {run_id} has no page items for document {document_id}.")
        page_output_payloads = list_ocr_page_output_payloads_for_document(
            connection,
            run_id=run_id,
            document_id=document_id,
        )
        if len(page_output_payloads) != len(page_rows):
            raise RetrieverError(
                f"OCR run {run_id} is missing page outputs for document {document_id}: "
                f"expected {len(page_rows)}, found {len(page_output_payloads)}."
            )
        merged_text = "\n\n".join(str(payload["text_content"]) for payload in page_output_payloads if str(payload["text_content"]).strip())
        created_text_revision_id = create_text_revision_row(
            connection,
            paths,
            document_id=document_id,
            revision_kind="ocr",
            text_content=merged_text,
            language=None,
            parent_revision_id=(
                int(snapshot_row["pinned_input_revision_id"])
                if snapshot_row["pinned_input_revision_id"] is not None
                else None
            ),
            created_by_job_version_id=int(job_version_row["id"]),
            quality_score=None,
            provider_metadata={
                "run_id": run_id,
                "page_count": len(page_output_payloads),
                "finalized_from": "ocr_page_outputs",
            },
        )
        result_id, _ = create_result_row(
            connection,
            run_id=run_id,
            document_id=document_id,
            job_version_id=int(job_version_row["id"]),
            input_revision_id=(
                int(snapshot_row["pinned_input_revision_id"])
                if snapshot_row["pinned_input_revision_id"] is not None
                else None
            ),
            input_identity=str(snapshot_row["pinned_input_identity"]),
            raw_output={
                "page_count": len(page_output_payloads),
                "finalized_from": "ocr_page_outputs",
            },
            normalized_output={
                "page_count": len(page_output_payloads),
                "created_text_revision_id": created_text_revision_id,
            },
            created_text_revision_id=created_text_revision_id,
            provider_metadata={
                "run_id": run_id,
                "page_count": len(page_output_payloads),
            },
        )
        connection.execute(
            """
            UPDATE run_items
            SET result_id = ?
            WHERE run_id = ?
              AND document_id = ?
            """,
            (result_id, run_id, document_id),
        )
        activation_payload = maybe_activate_created_text_revision(
            connection,
            paths,
            run_row=run_row,
            job_version_row=job_version_row,
            document_id=document_id,
            result_id=result_id,
            text_revision_id=created_text_revision_id,
        )
        if activation_payload is not None:
            activations.append(activation_payload)
        finalized_results.append(result_summary_by_id(connection, result_id))

    refresh_run_progress(connection, run_id)
    return {
        "status": "ok",
        "run": run_status_by_id(connection, run_id),
        "results": finalized_results,
        "activations": activations,
    }


def build_image_description_revision_text(page_output_payloads: list[dict[str, object]]) -> str:
    sections: list[str] = []
    for payload in page_output_payloads:
        page_number = int(payload["page_number"])
        text_content = normalize_whitespace(str(payload["text_content"] or ""))
        if not text_content:
            continue
        sections.append(f"[IMAGE DESCRIPTION - PAGE {page_number}]\n{text_content}")
    return "\n\n".join(sections)


def finalize_image_description_results_for_run(
    connection: sqlite3.Connection,
    paths: dict[str, Path],
    *,
    run_id: int,
) -> dict[str, object]:
    run_row = require_run_row_by_id(connection, run_id)
    job_version_row = require_job_version_row_by_id(connection, int(run_row["job_version_id"]))
    job_row = connection.execute(
        """
        SELECT *
        FROM jobs
        WHERE id = ?
        """,
        (job_version_row["job_id"],),
    ).fetchone()
    assert job_row is not None
    if normalize_job_kind(str(job_row["job_kind"])) != "image_description":
        raise RetrieverError("finalize-image-description-run only supports image_description jobs.")

    pending_counts = run_item_status_counts(connection, run_id)
    if pending_counts.get("pending", 0) or pending_counts.get("running", 0) or pending_counts.get("failed", 0):
        raise RetrieverError(
            "Image-description run cannot be finalized until all page items are completed. "
            f"pending={pending_counts.get('pending', 0)}, "
            f"running={pending_counts.get('running', 0)}, "
            f"failed={pending_counts.get('failed', 0)}."
        )

    snapshot_rows = connection.execute(
        """
        SELECT *
        FROM run_snapshot_documents
        WHERE run_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (run_id,),
    ).fetchall()
    finalized_results: list[dict[str, object]] = []
    activations: list[dict[str, object]] = []
    for snapshot_row in snapshot_rows:
        document_id = int(snapshot_row["document_id"])
        existing_result_row = find_active_result_row(
            connection,
            document_id=document_id,
            job_version_id=int(job_version_row["id"]),
            input_identity=str(snapshot_row["pinned_input_identity"]),
        )
        if existing_result_row is not None and existing_result_row["created_text_revision_id"] is not None:
            result_id = int(existing_result_row["id"])
            connection.execute(
                """
                UPDATE run_items
                SET result_id = ?
                WHERE run_id = ?
                  AND document_id = ?
                """,
                (result_id, run_id, document_id),
            )
            activation_payload = maybe_activate_created_text_revision(
                connection,
                paths,
                run_row=run_row,
                job_version_row=job_version_row,
                document_id=document_id,
                result_id=result_id,
                text_revision_id=int(existing_result_row["created_text_revision_id"]),
            )
            if activation_payload is not None:
                activations.append(activation_payload)
            finalized_results.append(result_summary_by_id(connection, result_id))
            continue

        page_rows = connection.execute(
            """
            SELECT *
            FROM run_items
            WHERE run_id = ?
              AND document_id = ?
              AND item_kind = 'page'
            ORDER BY page_number ASC, id ASC
            """,
            (run_id, document_id),
        ).fetchall()
        if not page_rows:
            raise RetrieverError(
                f"Image-description run {run_id} has no page items for document {document_id}."
            )
        page_output_payloads = list_image_description_page_output_payloads_for_document(
            connection,
            run_id=run_id,
            document_id=document_id,
        )
        if len(page_output_payloads) != len(page_rows):
            raise RetrieverError(
                f"Image-description run {run_id} is missing page outputs for document {document_id}: "
                f"expected {len(page_rows)}, found {len(page_output_payloads)}."
            )
        merged_text = build_image_description_revision_text(page_output_payloads)
        created_text_revision_id = create_text_revision_row(
            connection,
            paths,
            document_id=document_id,
            revision_kind="image_description",
            text_content=merged_text,
            language=None,
            parent_revision_id=(
                int(snapshot_row["pinned_input_revision_id"])
                if snapshot_row["pinned_input_revision_id"] is not None
                else None
            ),
            created_by_job_version_id=int(job_version_row["id"]),
            quality_score=None,
            provider_metadata={
                "run_id": run_id,
                "page_count": len(page_output_payloads),
                "finalized_from": "image_description_page_outputs",
            },
        )
        result_id, _ = create_result_row(
            connection,
            run_id=run_id,
            document_id=document_id,
            job_version_id=int(job_version_row["id"]),
            input_revision_id=(
                int(snapshot_row["pinned_input_revision_id"])
                if snapshot_row["pinned_input_revision_id"] is not None
                else None
            ),
            input_identity=str(snapshot_row["pinned_input_identity"]),
            raw_output={
                "page_count": len(page_output_payloads),
                "finalized_from": "image_description_page_outputs",
            },
            normalized_output={
                "page_count": len(page_output_payloads),
                "created_text_revision_id": created_text_revision_id,
            },
            created_text_revision_id=created_text_revision_id,
            provider_metadata={
                "run_id": run_id,
                "page_count": len(page_output_payloads),
            },
        )
        connection.execute(
            """
            UPDATE run_items
            SET result_id = ?
            WHERE run_id = ?
              AND document_id = ?
            """,
            (result_id, run_id, document_id),
        )
        activation_payload = maybe_activate_created_text_revision(
            connection,
            paths,
            run_row=run_row,
            job_version_row=job_version_row,
            document_id=document_id,
            result_id=result_id,
            text_revision_id=created_text_revision_id,
        )
        if activation_payload is not None:
            activations.append(activation_payload)
        finalized_results.append(result_summary_by_id(connection, result_id))

    refresh_run_progress(connection, run_id)
    return {
        "status": "ok",
        "run": run_status_by_id(connection, run_id),
        "results": finalized_results,
        "activations": activations,
    }


def coerce_result_output_value_for_publication(field_type: str, output_value: object) -> object:
    if output_value is None:
        return None
    if field_type == "text":
        return result_output_display_value(output_value)
    if isinstance(output_value, bool):
        raw_value = "true" if output_value else "false"
    elif isinstance(output_value, (int, float)):
        raw_value = str(output_value)
    elif isinstance(output_value, str):
        raw_value = output_value
    else:
        raw_value = compact_json_text(output_value)
    return value_from_type(field_type, raw_value)


def publish_result_outputs_for_run(
    connection: sqlite3.Connection,
    *,
    run_id: int,
    output_names: list[str] | None = None,
) -> dict[str, object]:
    normalized_output_names = {
        sanitize_processing_identifier(raw_name, label="Job output name", prefix="output")
        for raw_name in (output_names or [])
    }
    result_output_rows = connection.execute(
        """
        SELECT DISTINCT
          ro.id AS result_output_id,
          ro.result_id,
          ro.output_value_json,
          jo.id AS job_output_id,
          jo.output_name,
          jo.bound_custom_field,
          ri.document_id
        FROM run_items ri
        JOIN result_outputs ro ON ro.result_id = ri.result_id
        JOIN job_outputs jo ON jo.id = ro.job_output_id
        WHERE ri.run_id = ?
          AND ri.result_id IS NOT NULL
          AND jo.bound_custom_field IS NOT NULL
        ORDER BY ri.document_id ASC, jo.output_name ASC, ro.id ASC
        """,
        (run_id,),
    ).fetchall()
    published = 0
    affected_documents: set[int] = set()
    published_outputs: list[dict[str, object]] = []
    now = utc_now()
    for row in result_output_rows:
        output_name = str(row["output_name"])
        if normalized_output_names and output_name not in normalized_output_names:
            continue
        custom_field_name = str(row["bound_custom_field"] or "")
        field_def = resolve_field_definition(connection, custom_field_name)
        if field_def["source"] != "custom":
            raise RetrieverError(
                f"Bound field {custom_field_name!r} for output {output_name!r} must be a custom field."
            )
        document_id = int(row["document_id"])
        output_value = decode_json_text(row["output_value_json"])
        typed_value = coerce_result_output_value_for_publication(field_def["field_type"], output_value)
        connection.execute(
            f"""
            UPDATE documents
            SET {quote_identifier(field_def['field_name'])} = ?, updated_at = ?
            WHERE id = ?
            """,
            (typed_value, now, document_id),
        )
        connection.execute(
            """
            INSERT INTO publications (
              result_output_id,
              document_id,
              job_output_id,
              custom_field_name,
              published_at
            ) VALUES (?, ?, ?, ?, ?)
            """,
            (
                int(row["result_output_id"]),
                document_id,
                int(row["job_output_id"]),
                field_def["field_name"],
                now,
            ),
        )
        published += 1
        affected_documents.add(document_id)
        published_outputs.append(
            {
                "document_id": document_id,
                "result_id": int(row["result_id"]),
                "output_name": output_name,
                "custom_field_name": field_def["field_name"],
                "value": typed_value,
            }
        )
    return {
        "published_count": published,
        "document_count": len(affected_documents),
        "published_outputs": published_outputs,
    }


def run_summary_by_id(connection: sqlite3.Connection, run_id: int) -> dict[str, object]:
    row = connection.execute(
        """
        SELECT *
        FROM runs
        WHERE id = ?
        """,
        (run_id,),
    ).fetchone()
    if row is None:
        raise RetrieverError(f"Unknown run id: {run_id}")
    payload = run_row_to_payload(row)
    payload["job_version"] = job_version_summary_by_id(connection, int(row["job_version_id"]))
    snapshot_rows = connection.execute(
        """
        SELECT *
        FROM run_snapshot_documents
        WHERE run_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (run_id,),
    ).fetchall()
    payload["documents"] = [run_snapshot_document_row_to_payload(snapshot_row) for snapshot_row in snapshot_rows]
    return payload


def list_run_summaries(connection: sqlite3.Connection) -> list[dict[str, object]]:
    rows = connection.execute(
        """
        SELECT *
        FROM runs
        ORDER BY id DESC
        """
    ).fetchall()
    return [run_summary_by_id(connection, int(row["id"])) for row in rows]
def resolve_from_run_snapshot_rows(connection: sqlite3.Connection, from_run_id: int) -> list[sqlite3.Row]:
    run_row = connection.execute("SELECT id FROM runs WHERE id = ?", (from_run_id,)).fetchone()
    if run_row is None:
        raise RetrieverError(f"Unknown run id: {from_run_id}")
    return connection.execute(
        """
        SELECT *
        FROM run_snapshot_documents
        WHERE run_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (from_run_id,),
    ).fetchall()


def expand_seed_documents_with_family(
    connection: sqlite3.Connection,
    seed_document_ids: list[int],
    reasons_by_document_id: dict[int, dict[str, object]],
) -> list[int]:
    final_document_ids = list(seed_document_ids)
    seen_document_ids = set(seed_document_ids)
    if not seed_document_ids:
        return final_document_ids

    rows = connection.execute(
        f"""
        SELECT *
        FROM documents
        WHERE id IN ({', '.join('?' for _ in seed_document_ids)})
        """,
        seed_document_ids,
    ).fetchall()
    row_by_id = {int(row["id"]): row for row in rows}

    for seed_document_id in seed_document_ids:
        seed_row = row_by_id.get(seed_document_id)
        if seed_row is None:
            continue
        family_root_id = int(seed_row["parent_document_id"]) if seed_row["parent_document_id"] is not None else int(seed_row["id"])
        family_rows = connection.execute(
            """
            SELECT *
            FROM documents
            WHERE (id = ? OR parent_document_id = ?)
              AND lifecycle_status NOT IN ('missing', 'deleted')
            ORDER BY CASE WHEN id = ? THEN 0 ELSE 1 END ASC, id ASC
            """,
            (family_root_id, family_root_id, family_root_id),
        ).fetchall()
        for family_row in family_rows:
            family_document_id = int(family_row["id"])
            if family_document_id not in seen_document_ids:
                seen_document_ids.add(family_document_id)
                final_document_ids.append(family_document_id)
            reason_state = reasons_by_document_id.setdefault(
                family_document_id,
                {"direct_reasons": [], "family_seed_document_ids": []},
            )
            family_seed_ids = reason_state["family_seed_document_ids"]
            if seed_document_id not in family_seed_ids:
                family_seed_ids.append(seed_document_id)
    return final_document_ids


def compute_source_parts_content_hash(
    connection: sqlite3.Connection,
    *,
    root: Path,
    document_id: int,
) -> str | None:
    source_part_rows = connection.execute(
        """
        SELECT part_kind, rel_source_path, ordinal, label
        FROM document_source_parts
        WHERE document_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (document_id,),
    ).fetchall()
    if not source_part_rows:
        return None
    signature_parts: list[dict[str, object]] = []
    for row in source_part_rows:
        rel_source_path = normalize_whitespace(str(row["rel_source_path"] or ""))
        absolute_path = (root / rel_source_path).resolve() if rel_source_path else None
        file_hash = sha256_file(absolute_path) if absolute_path is not None and absolute_path.exists() else None
        signature_parts.append(
            {
                "part_kind": normalize_whitespace(str(row["part_kind"] or "")),
                "rel_source_path": rel_source_path,
                "ordinal": int(row["ordinal"] or 0),
                "label": normalize_whitespace(str(row["label"] or "")) or None,
                "file_hash": file_hash,
            }
        )
    return sha256_text(compact_json_text(signature_parts))


def compute_document_input_reference_for_job_version(
    connection: sqlite3.Connection,
    *,
    root: Path,
    document_row: sqlite3.Row,
    job_row: sqlite3.Row,
    job_version_row: sqlite3.Row,
    frozen_input_revision_id: int | None,
    frozen_content_hash: str | None,
) -> dict[str, object]:
    input_basis = str(job_version_row["input_basis"])
    job_kind = str(job_row["job_kind"])
    capability = normalize_whitespace(str(job_version_row["capability"] or ""))
    provider = normalize_whitespace(str(job_version_row["provider"] or ""))
    model = normalize_whitespace(str(job_version_row["model"] or ""))
    backend_id = capability or (f"{provider}:{model}" if model else provider)
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}

    if input_basis in {"active_search_text", "source_extract", "text_revision"}:
        if frozen_input_revision_id is not None:
            revision_id = int(frozen_input_revision_id)
        elif input_basis == "source_extract":
            revision_id = (
                int(document_row["source_text_revision_id"])
                if document_row["source_text_revision_id"] is not None
                else None
            )
        else:
            revision_id = (
                int(document_row["active_search_text_revision_id"])
                if document_row["active_search_text_revision_id"] is not None
                else None
            )
        if revision_id is None:
            raise RetrieverError(
                f"Document {document_row['id']} has no pinned text revision for input basis {input_basis!r}. Reingest the document first."
            )
        revision_row = connection.execute(
            """
            SELECT content_hash
            FROM text_revisions
            WHERE id = ? AND retracted_at IS NULL
            """,
            (revision_id,),
        ).fetchone()
        if revision_row is None:
            raise RetrieverError(f"Unknown active text revision id: {revision_id}")
        pinned_content_hash = frozen_content_hash or str(revision_row["content_hash"])
        if job_kind == "translation":
            target_language = (
                parameters.get("target_language")
                or parameters.get("target_lang")
                or parameters.get("language")
            )
            if not isinstance(target_language, str) or not target_language.strip():
                raise RetrieverError("Translation job versions require parameters_json.target_language.")
            input_identity = build_translation_input_identity(revision_id, target_language=target_language)
        else:
            input_identity = build_text_revision_input_identity(revision_id)
        return {
            "pinned_input_revision_id": revision_id,
            "pinned_input_identity": input_identity,
            "pinned_content_hash": pinned_content_hash,
        }

    if input_basis in {"source_file", "source_parts"}:
        source_hash = normalize_whitespace(str(frozen_content_hash or document_row["file_hash"] or ""))
        if not source_hash and input_basis == "source_parts":
            source_hash = normalize_whitespace(
                str(compute_source_parts_content_hash(connection, root=root, document_id=int(document_row["id"])) or "")
            )
        if not source_hash:
            raise RetrieverError(
                f"Document {document_row['id']} has no file hash for input basis {input_basis!r}."
            )
        if job_kind == "ocr":
            rendering_settings = parameters.get("rendering_settings")
            normalized_settings = rendering_settings if isinstance(rendering_settings, dict) else {}
            input_identity = build_ocr_input_identity(
                source_hash,
                rendering_settings=normalized_settings,
                backend_id=backend_id,
            )
        else:
            image_prep_settings = parameters.get("image_prep_settings")
            normalized_settings = image_prep_settings if isinstance(image_prep_settings, dict) else {}
            input_identity = build_image_source_input_identity(
                source_hash,
                image_prep_settings=normalized_settings,
                backend_id=backend_id,
            )
        return {
            "pinned_input_revision_id": None,
            "pinned_input_identity": input_identity,
            "pinned_content_hash": source_hash,
        }

    raise RetrieverError(f"Unsupported job input basis for run planning: {input_basis}")


def plan_scope_run_snapshot_rows(
    connection: sqlite3.Connection,
    *,
    root: Path,
    job_row: sqlite3.Row,
    job_version_row: sqlite3.Row,
    selector: dict[str, object],
    family_mode: str,
    seed_limit: int | None,
) -> list[dict[str, object]]:
    selected_documents, frozen_inputs_by_document_id = plan_scope_selected_documents(
        connection,
        selector=selector,
        family_mode=family_mode,
        seed_limit=seed_limit,
    )
    if not selected_documents:
        return []

    snapshot_rows: list[dict[str, object]] = []
    for selected_document in selected_documents:
        document_id = int(selected_document["document_id"])
        document_row = selected_document["document_row"]
        frozen_inputs = frozen_inputs_by_document_id.get(document_id, {})
        pinned_input = compute_document_input_reference_for_job_version(
            connection,
            root=root,
            document_row=document_row,
            job_row=job_row,
            job_version_row=job_version_row,
            frozen_input_revision_id=frozen_inputs.get("pinned_input_revision_id"),
            frozen_content_hash=frozen_inputs.get("pinned_content_hash"),
        )
        snapshot_rows.append(
            {
                "document_id": document_id,
                "ordinal": int(selected_document["ordinal"]),
                "inclusion_reason": selected_document["inclusion_reason"],
                "pinned_input_revision_id": pinned_input["pinned_input_revision_id"],
                "pinned_input_identity": pinned_input["pinned_input_identity"],
                "pinned_content_hash": pinned_input["pinned_content_hash"],
            }
        )
    return snapshot_rows


def scope_run_selector_has_inputs(selector: dict[str, object]) -> bool:
    return bool(scope_selector_instances(selector))


def scope_selector_reason_entries(scope: dict[str, object]) -> list[dict[str, object]]:
    reasons: list[dict[str, object]] = []
    keyword = normalize_inline_whitespace(str(scope.get("keyword") or ""))
    if keyword:
        reasons.append({"type": "keyword", "query": keyword})

    bates = scope.get("bates")
    if isinstance(bates, dict):
        begin = normalize_inline_whitespace(str(bates.get("begin") or ""))
        end = normalize_inline_whitespace(str(bates.get("end") or ""))
        if begin and end:
            reasons.append({"type": "bates", "begin": begin, "end": end})

    filter_expression = normalize_inline_whitespace(str(scope.get("filter") or ""))
    if filter_expression:
        reasons.append({"type": "filter", "expression": filter_expression})

    dataset_entries = coerce_scope_dataset_entries(scope.get("dataset"))
    if dataset_entries:
        reasons.append(
            {
                "type": "dataset",
                "dataset_ids": [int(entry["id"]) for entry in dataset_entries],
                "dataset_names": [str(entry["name"]) for entry in dataset_entries],
            }
        )

    if scope.get("from_run_id") is not None:
        reasons.append({"type": "from_run", "run_id": int(scope["from_run_id"])})
    return reasons


def resolve_seed_documents_for_scope_selector(
    connection: sqlite3.Connection,
    selector: dict[str, object],
) -> tuple[list[int], dict[int, dict[str, object]], dict[int, dict[str, object]]]:
    selector_instances = scope_selector_instances(selector)
    if not selector_instances:
        return [], {}, {}

    reasons_by_document_id: dict[int, dict[str, object]] = {}
    frozen_inputs_by_document_id: dict[int, dict[str, object]] = {}
    ordered_results: list[dict[str, object]] | None = None
    matching_document_ids: set[int] | None = None

    for selector_instance in selector_instances:
        selection = resolve_scope_document_search(connection, selector_instance)
        selection_scope = coerce_scope_payload(selection.get("scope"))
        selection_results = selection["results"]
        selection_document_ids = {int(item["id"]) for item in selection_results}
        if ordered_results is None:
            ordered_results = selection_results
            matching_document_ids = selection_document_ids
        else:
            assert matching_document_ids is not None
            matching_document_ids &= selection_document_ids

        direct_reasons = scope_selector_reason_entries(selection_scope)
        if direct_reasons:
            for item in selection_results:
                document_id = int(item["id"])
                reason_state = reasons_by_document_id.setdefault(
                    document_id,
                    {"direct_reasons": [], "family_seed_document_ids": []},
                )
                for reason in direct_reasons:
                    if reason not in reason_state["direct_reasons"]:
                        reason_state["direct_reasons"].append(reason)

        from_run_id = selection_scope.get("from_run_id")
        if from_run_id is not None:
            # Later selector clauses win so explicit --from-run-id narrows and pins over scope.
            for snapshot_row in resolve_from_run_snapshot_rows(connection, int(from_run_id)):
                document_id = int(snapshot_row["document_id"])
                frozen_inputs_by_document_id[document_id] = {
                    "pinned_input_revision_id": (
                        int(snapshot_row["pinned_input_revision_id"])
                        if snapshot_row["pinned_input_revision_id"] is not None
                        else None
                    ),
                    "pinned_content_hash": snapshot_row["pinned_content_hash"],
                }

    if ordered_results is None or matching_document_ids is None:
        return [], {}, {}

    ordered_matching_ids = [
        int(item["id"])
        for item in ordered_results
        if int(item["id"]) in matching_document_ids
    ]
    filtered_reasons = {
        document_id: reasons_by_document_id.get(
            document_id,
            {"direct_reasons": [], "family_seed_document_ids": []},
        )
        for document_id in ordered_matching_ids
    }
    filtered_frozen_inputs = {
        document_id: frozen_inputs
        for document_id, frozen_inputs in frozen_inputs_by_document_id.items()
        if document_id in matching_document_ids
    }
    return ordered_matching_ids, filtered_reasons, filtered_frozen_inputs


def plan_scope_selected_documents(
    connection: sqlite3.Connection,
    *,
    selector: dict[str, object],
    family_mode: str,
    seed_limit: int | None,
) -> tuple[list[dict[str, object]], dict[int, dict[str, object]]]:
    seed_document_ids, reasons_by_document_id, frozen_inputs_by_document_id = resolve_seed_documents_for_scope_selector(
        connection,
        selector,
    )
    if not seed_document_ids:
        return [], frozen_inputs_by_document_id

    if seed_limit is not None:
        seed_document_ids = seed_document_ids[:seed_limit]
    if family_mode == "with_family":
        final_document_ids = expand_seed_documents_with_family(connection, seed_document_ids, reasons_by_document_id)
    else:
        final_document_ids = list(seed_document_ids)
    if not final_document_ids:
        return [], frozen_inputs_by_document_id

    document_rows = connection.execute(
        f"""
        SELECT *
        FROM documents
        WHERE id IN ({', '.join('?' for _ in final_document_ids)})
        ORDER BY id ASC
        """,
        final_document_ids,
    ).fetchall()
    document_row_by_id = {int(row["id"]): row for row in document_rows}
    selected_documents: list[dict[str, object]] = []
    for ordinal, document_id in enumerate(final_document_ids):
        document_row = document_row_by_id.get(int(document_id))
        if document_row is None:
            continue
        selected_documents.append(
            {
                "document_id": int(document_id),
                "ordinal": ordinal,
                "document_row": document_row,
                "inclusion_reason": reasons_by_document_id.get(
                    int(document_id),
                    {"direct_reasons": [], "family_seed_document_ids": []},
                ),
            }
        )
    return selected_documents, frozen_inputs_by_document_id


def load_run_snapshot_rows(connection: sqlite3.Connection, run_id: int) -> list[sqlite3.Row]:
    return connection.execute(
        """
        SELECT *
        FROM run_snapshot_documents
        WHERE run_id = ?
        ORDER BY ordinal ASC, id ASC
        """,
        (run_id,),
    ).fetchall()


def load_text_input_for_snapshot_row(
    connection: sqlite3.Connection,
    paths: dict[str, Path],
    snapshot_row: sqlite3.Row,
) -> str | None:
    pinned_input_revision_id = snapshot_row["pinned_input_revision_id"]
    if pinned_input_revision_id is None:
        return None
    revision_row = require_text_revision_row_by_id(connection, int(pinned_input_revision_id))
    revision_body = read_text_revision_body(paths, revision_row["storage_rel_path"])
    if revision_body is None:
        raise RetrieverError(f"Text revision {pinned_input_revision_id} has no readable body on disk.")
    return revision_body


async def execute_run_async(
    connection: sqlite3.Connection,
    paths: dict[str, Path],
    *,
    run_id: int,
) -> dict[str, object]:
    run_row = connection.execute(
        """
        SELECT *
        FROM runs
        WHERE id = ?
        """,
        (run_id,),
    ).fetchone()
    if run_row is None:
        raise RetrieverError(f"Unknown run id: {run_id}")
    job_version_row = require_job_version_row_by_id(connection, int(run_row["job_version_id"]))
    job_row = connection.execute(
        """
        SELECT *
        FROM jobs
        WHERE id = ?
        """,
        (job_version_row["job_id"],),
    ).fetchone()
    assert job_row is not None
    job_kind = normalize_job_kind(str(job_row["job_kind"]))
    if job_kind not in {"structured_extraction", "translation"}:
        raise RetrieverError(
            "Run execution currently supports structured_extraction and translation jobs only."
        )
    snapshot_rows = load_run_snapshot_rows(connection, run_id)
    job_output_rows = connection.execute(
        """
        SELECT *
        FROM job_outputs
        WHERE job_id = ?
        ORDER BY ordinal ASC, output_name ASC, id ASC
        """,
        (job_row["id"],),
    ).fetchall()

    connection.execute(
        """
        UPDATE runs
        SET status = 'running',
            started_at = COALESCE(started_at, ?),
            completed_at = NULL,
            canceled_at = NULL
        WHERE id = ?
        """,
        (utc_now(), run_id),
    )
    connection.commit()

    for snapshot_row in snapshot_rows:
        run_item_row = ensure_run_item_row(
            connection,
            run_id=run_id,
            run_snapshot_document_id=int(snapshot_row["id"]),
            item_kind="document",
            document_id=int(snapshot_row["document_id"]),
            input_identity=str(snapshot_row["pinned_input_identity"]),
        )
        existing_result_row = find_active_result_row(
            connection,
            document_id=int(snapshot_row["document_id"]),
            job_version_id=int(job_version_row["id"]),
            input_identity=str(snapshot_row["pinned_input_identity"]),
        )
        if existing_result_row is not None:
            maybe_activate_created_text_revision(
                connection,
                paths,
                run_row=run_row,
                job_version_row=job_version_row,
                document_id=int(snapshot_row["document_id"]),
                result_id=int(existing_result_row["id"]),
                text_revision_id=(
                    int(existing_result_row["created_text_revision_id"])
                    if existing_result_row["created_text_revision_id"] is not None
                    else None
                ),
            )
            terminal_status = str(run_item_row["status"] or "")
            if terminal_status not in {"completed", "skipped"} or run_item_row["result_id"] != existing_result_row["id"]:
                update_run_item_row(
                    connection,
                    run_item_id=int(run_item_row["id"]),
                    status="skipped",
                    result_id=int(existing_result_row["id"]),
                    last_error=None,
                    completed_at=utc_now(),
                )
                connection.commit()
            continue

        started_at = utc_now()
        update_run_item_row(
            connection,
            run_item_id=int(run_item_row["id"]),
            status="running",
            result_id=None,
            last_error=None,
            started_at=(run_item_row["started_at"] or started_at),
            completed_at=None,
        )
        connection.commit()

        attempt_started = time.perf_counter()
        try:
            document_row = connection.execute(
                """
                SELECT *
                FROM documents
                WHERE id = ?
                """,
                (snapshot_row["document_id"],),
            ).fetchone()
            if document_row is None:
                raise RetrieverError(f"Unknown document id: {snapshot_row['document_id']}")
            text_input = load_text_input_for_snapshot_row(connection, paths, snapshot_row)
            provider_result = await execute_job_provider(
                job_row=job_row,
                job_version_row=job_version_row,
                job_output_rows=job_output_rows,
                document_row=document_row,
                text_input=text_input,
            )
            created_text_revision_id = None
            created_text_revision_payload = provider_result.get("created_text_revision")
            if isinstance(created_text_revision_payload, dict):
                created_text_content = str(created_text_revision_payload.get("text_content") or "")
                created_text_revision_id = create_text_revision_row(
                    connection,
                    paths,
                    document_id=int(snapshot_row["document_id"]),
                    revision_kind=str(created_text_revision_payload.get("revision_kind") or "translation"),
                    text_content=created_text_content,
                    language=(
                        str(created_text_revision_payload["language"])
                        if created_text_revision_payload.get("language")
                        else None
                    ),
                    parent_revision_id=(
                        int(snapshot_row["pinned_input_revision_id"])
                        if snapshot_row["pinned_input_revision_id"] is not None
                        else None
                    ),
                    created_by_job_version_id=int(job_version_row["id"]),
                    quality_score=None,
                    provider_metadata=provider_result.get("provider_metadata"),  # type: ignore[arg-type]
                )
            latency_ms = int((time.perf_counter() - attempt_started) * 1000)
            result_id, created = create_result_row(
                connection,
                run_id=run_id,
                document_id=int(snapshot_row["document_id"]),
                job_version_id=int(job_version_row["id"]),
                input_revision_id=(
                    int(snapshot_row["pinned_input_revision_id"])
                    if snapshot_row["pinned_input_revision_id"] is not None
                    else None
                ),
                input_identity=str(snapshot_row["pinned_input_identity"]),
                raw_output=provider_result["raw_output"],
                normalized_output=provider_result["normalized_output"],
                created_text_revision_id=created_text_revision_id,
                provider_metadata=provider_result["provider_metadata"],  # type: ignore[arg-type]
            )
            if created and job_output_rows:
                upsert_result_output_rows(
                    connection,
                    result_id=result_id,
                    job_output_rows=job_output_rows,
                    output_values_by_name=provider_result["output_values"],  # type: ignore[arg-type]
                )
            maybe_activate_created_text_revision(
                connection,
                paths,
                run_row=run_row,
                job_version_row=job_version_row,
                document_id=int(snapshot_row["document_id"]),
                result_id=result_id,
                text_revision_id=created_text_revision_id,
            )
            create_attempt_row(
                connection,
                run_item_id=int(run_item_row["id"]),
                provider_request_id=provider_result["provider_request_id"],  # type: ignore[arg-type]
                input_tokens=provider_result["input_tokens"],  # type: ignore[arg-type]
                output_tokens=provider_result["output_tokens"],  # type: ignore[arg-type]
                cost_cents=provider_result["cost_cents"],  # type: ignore[arg-type]
                latency_ms=latency_ms,
                provider_metadata=provider_result["provider_metadata"],  # type: ignore[arg-type]
                error_summary=None,
            )
            update_run_item_row(
                connection,
                run_item_id=int(run_item_row["id"]),
                status="completed",
                result_id=result_id,
                last_error=None,
                completed_at=utc_now(),
                increment_attempt_count=True,
            )
            connection.commit()
        except Exception as exc:
            latency_ms = int((time.perf_counter() - attempt_started) * 1000)
            error_summary = f"{type(exc).__name__}: {exc}"
            create_attempt_row(
                connection,
                run_item_id=int(run_item_row["id"]),
                provider_request_id=None,
                input_tokens=None,
                output_tokens=None,
                cost_cents=None,
                latency_ms=latency_ms,
                provider_metadata={"phase": "execute_run"},
                error_summary=error_summary,
            )
            update_run_item_row(
                connection,
                run_item_id=int(run_item_row["id"]),
                status="failed",
                result_id=None,
                last_error=error_summary,
                completed_at=utc_now(),
                increment_attempt_count=True,
            )
            connection.commit()

    refresh_run_progress(connection, run_id)
    connection.commit()
    return {
        "status": "ok",
        "run": run_summary_by_id(connection, run_id),
        "run_items": list_run_item_payloads_for_run(connection, run_id),
        "results": list_result_summaries(connection, run_id=run_id),
    }
def job_output_schema_fragment(value_type: str) -> dict[str, object]:
    normalized_value_type = normalize_job_output_value_type(value_type)
    if normalized_value_type == "boolean":
        return {"type": "boolean"}
    if normalized_value_type == "date":
        return {"type": "string", "description": "ISO-8601 date string"}
    if normalized_value_type == "integer":
        return {"type": "integer"}
    if normalized_value_type == "json":
        return {"type": "object"}
    if normalized_value_type == "real":
        return {"type": "number"}
    return {"type": "string"}


def derive_job_output_response_schema(job_output_rows: list[sqlite3.Row]) -> dict[str, object]:
    properties: dict[str, object] = {}
    required: list[str] = []
    for row in job_output_rows:
        output_name = str(row["output_name"])
        properties[output_name] = job_output_schema_fragment(str(row["value_type"]))
        required.append(output_name)
    return {
        "type": "object",
        "properties": properties,
        "required": required,
        "additionalProperties": False,
    }


def default_job_output_value(value_type: str) -> object:
    normalized_value_type = normalize_job_output_value_type(value_type)
    if normalized_value_type == "boolean":
        return False
    if normalized_value_type == "integer":
        return 0
    if normalized_value_type == "real":
        return 0
    if normalized_value_type == "json":
        return {}
    return ""


def build_text_structured_execution_payload(
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
) -> dict[str, object]:
    output_defaults = {
        str(row["output_name"]): default_job_output_value(str(row["value_type"]))
        for row in job_output_rows
    }
    instruction_text = normalize_whitespace(str(job_version_row["instruction_text"] or ""))
    prompt_lines = [
        "Read the provided document text and extract the requested outputs.",
        "Return only a JSON object that matches response_schema exactly.",
        "If a value cannot be determined, use the matching fallback value from output_defaults.",
    ]
    if instruction_text:
        prompt_lines.append(f"Job instruction: {instruction_text}")
    return {
        "capability": "text_structured",
        "task_prompt": "\n".join(prompt_lines),
        "output_defaults": output_defaults,
        "completion_command": "complete-run-item",
        "completion_template": {
            "raw_output_json": {key: f"<raw {key} value>" for key in output_defaults},
            "normalized_output_json": {key: f"<normalized {key} value>" for key in output_defaults},
            "output_values_json": {key: f"<final {key} value>" for key in output_defaults},
        },
    }


def build_translation_execution_payload(job_version_row: sqlite3.Row) -> dict[str, object]:
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    target_language = normalize_whitespace(
        str(
            parameters.get("target_language")
            or parameters.get("target_lang")
            or parameters.get("language")
            or ""
        )
    )
    instruction_text = normalize_whitespace(str(job_version_row["instruction_text"] or ""))
    prompt_lines = [
        f"Translate the entire input text into {target_language or 'the requested target language'}.",
        "Return only the translated text, with no JSON wrapper or commentary.",
    ]
    if instruction_text:
        prompt_lines.append(f"Job instruction: {instruction_text}")
    return {
        "capability": "text_translation",
        "target_language": target_language or None,
        "task_prompt": "\n".join(prompt_lines),
        "completion_command": "complete-run-item",
        "completion_template": {
            "raw_output_json": {
                "translated_text": "<translated text>",
                "target_language": target_language or "<target language>",
            },
            "normalized_output_json": {
                "translated_text": "<translated text>",
                "target_language": target_language or "<target language>",
            },
            "created_text_revision_json": {
                "revision_kind": "translation",
                "language": target_language or "<target language>",
                "text_content": "<translated text>",
            },
        },
    }


def build_vision_ocr_execution_payload(job_version_row: sqlite3.Row) -> dict[str, object]:
    instruction_text = normalize_whitespace(str(job_version_row["instruction_text"] or ""))
    prompt_lines = [
        "Read the page image and transcribe all readable text in natural reading order.",
        "Return plain text only. Do not wrap the output in JSON or Markdown.",
    ]
    if instruction_text:
        prompt_lines.append(f"Job instruction: {instruction_text}")
    return {
        "capability": "vision_ocr",
        "task_prompt": "\n".join(prompt_lines),
        "completion_command": "complete-run-item",
        "completion_template": {
            "page_text": "<ocr page text>",
        },
    }


def build_vision_description_execution_payload(job_version_row: sqlite3.Row) -> dict[str, object]:
    instruction_text = normalize_whitespace(str(job_version_row["instruction_text"] or ""))
    prompt_lines = [
        "Describe the page image in clear, search-friendly prose.",
        "Prioritize visible people, objects, scenes, charts, handwriting, stamps, and other salient visual details.",
        "Return plain text only. Do not wrap the output in JSON or Markdown.",
    ]
    if instruction_text:
        prompt_lines.append(f"Job instruction: {instruction_text}")
    return {
        "capability": "vision_description",
        "task_prompt": "\n".join(prompt_lines),
        "completion_command": "complete-run-item",
        "completion_template": {
            "page_text": "<image description text>",
        },
    }


def build_capability_execution_payload(
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
) -> dict[str, object] | None:
    capability = normalize_whitespace(str(job_version_row["capability"] or ""))
    if capability == "text_structured":
        return build_text_structured_execution_payload(job_version_row, job_output_rows)
    if capability == "text_translation":
        return build_translation_execution_payload(job_version_row)
    if capability == "vision_description":
        return build_vision_description_execution_payload(job_version_row)
    if capability == "vision_ocr":
        return build_vision_ocr_execution_payload(job_version_row)
    return None


def best_effort_document_source_path(root: Path, document_row: sqlite3.Row) -> str | None:
    source_rel_path = normalize_whitespace(str(document_row["source_rel_path"] or ""))
    if not source_rel_path:
        return None
    candidate = (root / source_rel_path).resolve()
    if candidate.exists():
        return str(candidate)
    return None


def build_text_input_reference(
    paths: dict[str, Path],
    revision_row: sqlite3.Row,
    *,
    inline_bytes: int = DEFAULT_RUN_ITEM_CONTEXT_INLINE_BYTES,
) -> dict[str, object]:
    revision_body = read_text_revision_body(paths, revision_row["storage_rel_path"])
    if revision_body is None:
        raise RetrieverError(f"Text revision {revision_row['id']} has no readable body on disk.")
    encoded_size = len(revision_body.encode("utf-8"))
    storage_path = str((paths["state_dir"] / str(revision_row["storage_rel_path"])).resolve())
    return {
        "kind": "text_revision",
        "text_revision_id": int(revision_row["id"]),
        "inline_text": revision_body if encoded_size <= inline_bytes else None,
        "text_path": None if encoded_size <= inline_bytes else storage_path,
        "bytes": encoded_size,
    }


def build_run_item_context_payload(
    connection: sqlite3.Connection,
    paths: dict[str, Path],
    root: Path,
    run_item_row: sqlite3.Row,
    *,
    inline_bytes: int = DEFAULT_RUN_ITEM_CONTEXT_INLINE_BYTES,
) -> dict[str, object]:
    run_row = require_run_row_by_id(connection, int(run_item_row["run_id"]))
    job_version_row = require_job_version_row_by_id(connection, int(run_row["job_version_id"]))
    job_row = connection.execute(
        """
        SELECT *
        FROM jobs
        WHERE id = ?
        """,
        (job_version_row["job_id"],),
    ).fetchone()
    assert job_row is not None
    snapshot_row = None
    if run_item_row["run_snapshot_document_id"] is not None:
        snapshot_row = connection.execute(
            """
            SELECT *
            FROM run_snapshot_documents
            WHERE id = ?
            """,
            (run_item_row["run_snapshot_document_id"],),
        ).fetchone()
    document_row = connection.execute(
        """
        SELECT *
        FROM documents
        WHERE id = ?
        """,
        (run_item_row["document_id"],),
    ).fetchone()
    if document_row is None:
        raise RetrieverError(f"Unknown document id: {run_item_row['document_id']}")
    job_output_rows = connection.execute(
        """
        SELECT *
        FROM job_outputs
        WHERE job_id = ?
        ORDER BY ordinal ASC, output_name ASC, id ASC
        """,
        (job_row["id"],),
    ).fetchall()
    response_schema = decode_json_text(job_version_row["response_schema_json"])
    if response_schema is None and str(job_version_row["capability"]) == "text_structured":
        response_schema = derive_job_output_response_schema(job_output_rows)

    item_kind = str(run_item_row["item_kind"] or "")
    if item_kind == "page":
        artifact_rel_path = normalize_whitespace(str(run_item_row["input_artifact_rel_path"] or ""))
        artifact_path = resolve_workspace_artifact_path(root, artifact_rel_path)
        if artifact_path is None or not artifact_path.exists():
            raise RetrieverError(f"Run item {run_item_row['id']} points at a missing OCR artifact: {artifact_rel_path!r}")
        page_input_kind = (
            "image_description_page_image"
            if normalize_job_kind(str(job_row["job_kind"])) == "image_description"
            else "ocr_page_image"
        )
        input_payload = {
            "kind": page_input_kind,
            "page_number": int(run_item_row["page_number"] or 0),
            "artifact_rel_path": artifact_rel_path,
            "artifact_path": str(artifact_path),
            "bytes": artifact_path.stat().st_size,
            "text_revision_id": None,
            "inline_text": None,
            "text_path": None,
            "source_path": best_effort_document_source_path(root, document_row),
            "source_rel_path": document_row["source_rel_path"],
            "file_hash": document_row["file_hash"],
        }
    elif snapshot_row is not None and snapshot_row["pinned_input_revision_id"] is not None:
        revision_row = require_text_revision_row_by_id(connection, int(snapshot_row["pinned_input_revision_id"]))
        input_payload = build_text_input_reference(paths, revision_row, inline_bytes=inline_bytes)
    else:
        input_payload = {
            "kind": str(job_version_row["input_basis"]),
            "text_revision_id": None,
            "inline_text": None,
            "text_path": None,
            "bytes": None,
            "source_path": best_effort_document_source_path(root, document_row),
            "source_rel_path": document_row["source_rel_path"],
            "file_hash": document_row["file_hash"],
        }

    return {
        "run": run_row_to_payload(run_row),
        "run_item": run_item_row_to_payload(run_item_row),
        "job": job_row_to_payload(job_row),
        "job_version": job_version_row_to_payload(job_version_row),
        "job_outputs": [job_output_row_to_payload(row) for row in job_output_rows],
        "response_schema": response_schema,
        "execution": build_capability_execution_payload(job_version_row, job_output_rows),
        "document": {
            "id": int(document_row["id"]),
            "file_name": document_row["file_name"],
            "file_type": document_row["file_type"],
            "source_kind": document_row["source_kind"],
            "source_rel_path": document_row["source_rel_path"],
            "source_path": best_effort_document_source_path(root, document_row),
            "active_search_text_revision_id": document_row["active_search_text_revision_id"],
            "source_text_revision_id": document_row["source_text_revision_id"],
        },
        "input": input_payload,
        "inclusion_reason": (
            decode_json_text(snapshot_row["inclusion_reason_json"], default={}) or {}
            if snapshot_row is not None
            else {}
        ),
    }
OPENAI_RESPONSES_PROVIDER_NAMES = {"openai", "openai_responses"}
STATIC_STRUCTURED_EXTRACTION_PROVIDER_NAMES = {"builtin_static_json", "static_json"}
STATIC_TRANSLATION_PROVIDER_NAMES = {"builtin_static_text", "static_text"}
OPENAI_RESPONSES_DEFAULT_URL = "https://api.openai.com/v1/responses"


def render_processing_template_value(value: object, context: dict[str, object]) -> object:
    if isinstance(value, str):
        normalized_context = defaultdict(
            str,
            {
                key: "" if item is None else str(item)
                for key, item in context.items()
            },
        )
        try:
            return value.format_map(normalized_context)
        except Exception:
            return value
    if isinstance(value, list):
        return [render_processing_template_value(item, context) for item in value]
    if isinstance(value, dict):
        return {
            str(key): render_processing_template_value(item, context)
            for key, item in value.items()
        }
    return value


def processing_job_output_json_schema(job_output_rows: list[sqlite3.Row]) -> dict[str, object]:
    properties: dict[str, object] = {}
    required: list[str] = []
    for job_output_row in job_output_rows:
        output_name = str(job_output_row["output_name"])
        value_type = normalize_job_output_value_type(str(job_output_row["value_type"] or "text"))
        schema: dict[str, object]
        if value_type == "boolean":
            schema = {"type": "boolean"}
        elif value_type == "date":
            schema = {"type": "string"}
        elif value_type == "integer":
            schema = {"type": "integer"}
        elif value_type == "real":
            schema = {"type": "number"}
        elif value_type == "json":
            schema = {
                "type": "object",
                "additionalProperties": True,
            }
        else:
            schema = {"type": "string"}
        properties[output_name] = schema
        required.append(output_name)
    return {
        "type": "object",
        "properties": properties,
        "required": required,
        "additionalProperties": False,
    }


def processing_response_schema(
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
) -> dict[str, object]:
    parsed = decode_json_text(job_version_row["response_schema_json"])
    if isinstance(parsed, dict) and parsed:
        return parsed
    return processing_job_output_json_schema(job_output_rows)


def openai_responses_api_url() -> str:
    explicit_url = normalize_whitespace(os.environ.get("OPENAI_RESPONSES_URL", ""))
    if explicit_url:
        return explicit_url
    base_url = normalize_whitespace(os.environ.get("OPENAI_BASE_URL", ""))
    if base_url:
        return base_url.rstrip("/") + "/responses"
    return OPENAI_RESPONSES_DEFAULT_URL


def openai_api_key() -> str:
    api_key = normalize_whitespace(os.environ.get("OPENAI_API_KEY", ""))
    if not api_key:
        raise RetrieverError("OPENAI_API_KEY is required for openai_responses providers.")
    return api_key


def openai_response_text(response_payload: dict[str, object]) -> str:
    top_level_output_text = response_payload.get("output_text")
    if isinstance(top_level_output_text, str) and top_level_output_text.strip():
        return top_level_output_text
    output_items = response_payload.get("output")
    if not isinstance(output_items, list):
        raise RetrieverError("OpenAI response payload did not contain output text.")
    text_parts: list[str] = []
    for output_item in output_items:
        if not isinstance(output_item, dict):
            continue
        content_items = output_item.get("content")
        if not isinstance(content_items, list):
            continue
        for content_item in content_items:
            if not isinstance(content_item, dict):
                continue
            if str(content_item.get("type") or "") != "output_text":
                continue
            text_value = content_item.get("text")
            if isinstance(text_value, str):
                text_parts.append(text_value)
    if text_parts:
        return "".join(text_parts)
    raise RetrieverError("OpenAI response payload did not contain output_text content.")


def openai_response_usage(response_payload: dict[str, object]) -> tuple[int | None, int | None]:
    usage = response_payload.get("usage")
    if not isinstance(usage, dict):
        return None, None
    input_tokens = usage.get("input_tokens")
    output_tokens = usage.get("output_tokens")
    return (
        int(input_tokens) if isinstance(input_tokens, int) else None,
        int(output_tokens) if isinstance(output_tokens, int) else None,
    )


def call_openai_responses_api(
    *,
    payload: dict[str, object],
    timeout_seconds: float,
) -> dict[str, object]:
    request_bytes = compact_json_text(payload).encode("utf-8")
    request = urllib_request.Request(
        openai_responses_api_url(),
        data=request_bytes,
        headers={
            "Authorization": f"Bearer {openai_api_key()}",
            "Content-Type": "application/json",
        },
        method="POST",
    )
    try:
        with urllib_request.urlopen(request, timeout=timeout_seconds) as response:
            response_body = response.read().decode("utf-8")
    except urllib_error.HTTPError as exc:
        error_body = exc.read().decode("utf-8", errors="replace")
        raise RetrieverError(f"OpenAI Responses API request failed: HTTP {exc.code}: {error_body}") from exc
    except urllib_error.URLError as exc:
        raise RetrieverError(f"OpenAI Responses API request failed: {exc.reason}") from exc

    try:
        parsed = json.loads(response_body)
    except (TypeError, ValueError, json.JSONDecodeError) as exc:
        raise RetrieverError("OpenAI Responses API returned invalid JSON.") from exc
    if not isinstance(parsed, dict):
        raise RetrieverError("OpenAI Responses API returned an unexpected response shape.")
    return parsed


def response_api_request_overrides(parameters: dict[str, object]) -> dict[str, object]:
    overrides: dict[str, object] = {}
    for key in (
        "max_output_tokens",
        "metadata",
        "reasoning",
        "service_tier",
        "temperature",
        "top_p",
        "truncation",
    ):
        if key in parameters:
            overrides[key] = parameters[key]
    return overrides


def processing_input_context(document_row: sqlite3.Row, text_input: str | None) -> dict[str, object]:
    return {
        "document_id": int(document_row["id"]),
        "control_number": document_row["control_number"],
        "file_name": document_row["file_name"],
        "rel_path": document_row["rel_path"],
        "title": document_row["title"],
        "subject": document_row["subject"],
        "text": text_input or "",
    }


def execute_static_structured_extraction_provider(
    *,
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
    document_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    output_values = parameters.get("output_values")
    if not isinstance(output_values, dict):
        raise RetrieverError("static_json structured extraction requires parameters_json.output_values to be an object.")
    context = processing_input_context(document_row, text_input)
    normalized_outputs: dict[str, object] = {}
    for job_output_row in job_output_rows:
        output_name = str(job_output_row["output_name"])
        normalized_outputs[output_name] = render_processing_template_value(output_values.get(output_name), context)
    output_json = compact_json_text(normalized_outputs)
    return {
        "raw_output": normalized_outputs,
        "normalized_output": normalized_outputs,
        "output_values": normalized_outputs,
        "provider_request_id": None,
        "input_tokens": token_estimate(text_input or "") if text_input is not None else None,
        "output_tokens": token_estimate(output_json) if normalized_outputs else 0,
        "cost_cents": 0,
        "provider_metadata": {
            "provider": str(job_version_row["provider"]),
            "model": job_version_row["model"],
            "executed_by": "structured_extraction_static_provider",
        },
    }


def build_openai_structured_extraction_payload(
    *,
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
    document_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    model = normalize_whitespace(str(job_version_row["model"] or ""))
    if not model:
        raise RetrieverError("openai_responses structured extraction requires a model name.")
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    instruction_text = str(job_version_row["instruction_text"] or "").strip() or "Extract the requested structured outputs."
    schema = processing_response_schema(job_version_row, job_output_rows)
    schema_name = sanitize_processing_identifier(
        str(job_version_row["display_name"] or f"job_version_{job_version_row['id']}"),
        label="Schema name",
        prefix="schema",
    )[:64]
    user_content = (
        "Return structured JSON for the following document text.\n\n"
        f"<document>\n{text_input or ''}\n</document>"
    )
    payload: dict[str, object] = {
        "model": model,
        "store": False,
        "input": [
            {"role": "system", "content": instruction_text},
            {"role": "user", "content": user_content},
        ],
        "text": {
            "format": {
                "type": "json_schema",
                "name": schema_name,
                "schema": schema,
                "strict": True,
            }
        },
    }
    payload.update(response_api_request_overrides(parameters))
    return payload


def execute_openai_structured_extraction_provider(
    *,
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
    document_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    timeout_seconds = float(parameters.get("timeout_seconds") or 60.0)
    request_payload = build_openai_structured_extraction_payload(
        job_version_row=job_version_row,
        job_output_rows=job_output_rows,
        document_row=document_row,
        text_input=text_input,
    )
    response_payload = call_openai_responses_api(
        payload=request_payload,
        timeout_seconds=timeout_seconds,
    )
    output_text = openai_response_text(response_payload)
    try:
        normalized_outputs = json.loads(output_text)
    except (TypeError, ValueError, json.JSONDecodeError) as exc:
        raise RetrieverError("OpenAI structured extraction did not return valid JSON.") from exc
    if not isinstance(normalized_outputs, dict):
        raise RetrieverError("OpenAI structured extraction must return a JSON object.")
    input_tokens, output_tokens = openai_response_usage(response_payload)
    return {
        "raw_output": response_payload,
        "normalized_output": normalized_outputs,
        "output_values": normalized_outputs,
        "provider_request_id": response_payload.get("id"),
        "input_tokens": input_tokens,
        "output_tokens": output_tokens,
        "cost_cents": None,
        "provider_metadata": {
            "provider": str(job_version_row["provider"]),
            "model": job_version_row["model"],
            "response_id": response_payload.get("id"),
            "status": response_payload.get("status"),
        },
    }


def execute_static_translation_provider(
    *,
    job_version_row: sqlite3.Row,
    document_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    translated_template = parameters.get("translated_text")
    if translated_template is None:
        raise RetrieverError("static_text translation requires parameters_json.translated_text.")
    context = processing_input_context(document_row, text_input)
    translated_text = render_processing_template_value(translated_template, context)
    if not isinstance(translated_text, str):
        translated_text = compact_json_text(translated_text)
    target_language = normalize_whitespace(
        str(parameters.get("target_language") or parameters.get("target_lang") or parameters.get("language") or "")
    ).lower() or None
    return {
        "raw_output": {"translated_text": translated_text},
        "normalized_output": {"translated_text": translated_text},
        "output_values": {},
        "created_text_revision": {
            "revision_kind": "translation",
            "text_content": translated_text,
            "language": target_language,
        },
        "provider_request_id": None,
        "input_tokens": token_estimate(text_input or "") if text_input is not None else None,
        "output_tokens": token_estimate(translated_text),
        "cost_cents": 0,
        "provider_metadata": {
            "provider": str(job_version_row["provider"]),
            "model": job_version_row["model"],
            "executed_by": "translation_static_provider",
            "target_language": target_language,
        },
    }


def build_openai_translation_payload(
    *,
    job_version_row: sqlite3.Row,
    text_input: str | None,
) -> tuple[dict[str, object], str | None]:
    model = normalize_whitespace(str(job_version_row["model"] or ""))
    if not model:
        raise RetrieverError("openai_responses translation requires a model name.")
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    target_language = normalize_whitespace(
        str(parameters.get("target_language") or parameters.get("target_lang") or parameters.get("language") or "")
    ).lower()
    if not target_language:
        raise RetrieverError("Translation job versions require parameters_json.target_language.")
    instruction_text = str(job_version_row["instruction_text"] or "").strip() or (
        f"Translate the document into {target_language}. Return only the translated text."
    )
    payload: dict[str, object] = {
        "model": model,
        "store": False,
        "input": [
            {"role": "system", "content": instruction_text},
            {
                "role": "user",
                "content": f"<document>\n{text_input or ''}\n</document>",
            },
        ],
        "text": {"format": {"type": "text"}},
    }
    payload.update(response_api_request_overrides(parameters))
    return payload, target_language


def execute_openai_translation_provider(
    *,
    job_version_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    parameters = decode_json_text(job_version_row["parameters_json"], default={}) or {}
    if not isinstance(parameters, dict):
        parameters = {}
    timeout_seconds = float(parameters.get("timeout_seconds") or 60.0)
    request_payload, target_language = build_openai_translation_payload(
        job_version_row=job_version_row,
        text_input=text_input,
    )
    response_payload = call_openai_responses_api(
        payload=request_payload,
        timeout_seconds=timeout_seconds,
    )
    translated_text = openai_response_text(response_payload)
    input_tokens, output_tokens = openai_response_usage(response_payload)
    return {
        "raw_output": response_payload,
        "normalized_output": {"translated_text": translated_text},
        "output_values": {},
        "created_text_revision": {
            "revision_kind": "translation",
            "text_content": translated_text,
            "language": target_language,
        },
        "provider_request_id": response_payload.get("id"),
        "input_tokens": input_tokens,
        "output_tokens": output_tokens,
        "cost_cents": None,
        "provider_metadata": {
            "provider": str(job_version_row["provider"]),
            "model": job_version_row["model"],
            "response_id": response_payload.get("id"),
            "status": response_payload.get("status"),
            "target_language": target_language,
        },
    }


async def execute_job_provider(
    *,
    job_row: sqlite3.Row,
    job_version_row: sqlite3.Row,
    job_output_rows: list[sqlite3.Row],
    document_row: sqlite3.Row,
    text_input: str | None,
) -> dict[str, object]:
    provider = normalize_whitespace(str(job_version_row["provider"] or "")).lower()
    job_kind = normalize_job_kind(str(job_row["job_kind"]))

    if job_kind == "structured_extraction":
        if provider in STATIC_STRUCTURED_EXTRACTION_PROVIDER_NAMES:
            return execute_static_structured_extraction_provider(
                job_version_row=job_version_row,
                job_output_rows=job_output_rows,
                document_row=document_row,
                text_input=text_input,
            )
        if provider in OPENAI_RESPONSES_PROVIDER_NAMES:
            return await asyncio.to_thread(
                execute_openai_structured_extraction_provider,
                job_version_row=job_version_row,
                job_output_rows=job_output_rows,
                document_row=document_row,
                text_input=text_input,
            )

    if job_kind == "translation":
        if provider in STATIC_TRANSLATION_PROVIDER_NAMES:
            return execute_static_translation_provider(
                job_version_row=job_version_row,
                document_row=document_row,
                text_input=text_input,
            )
        if provider in OPENAI_RESPONSES_PROVIDER_NAMES:
            return await asyncio.to_thread(
                execute_openai_translation_provider,
                job_version_row=job_version_row,
                text_input=text_input,
            )

    raise RetrieverError(
        f"Unsupported job execution provider {provider!r} for job kind {job_kind!r}."
    )
